window.JIKJI_I18N["it"]={
 "a11y.skip": "Vai al contenuto principale",
 "a11y.language": "Lingua",
 "a11y.nav.open": "Apri navigazione",
 "a11y.nav.close": "Chiudi navigazione",
 "nav.arch": "Architettura",
 "nav.loop": "Ciclo dell'agente",
 "nav.tools": "Strumenti",
 "nav.orch": "Orchestrazione",
 "nav.memory": "Memoria &amp; dati",
 "nav.ontology": "Ontologia",
 "nav.enterprise": "Enterprise",
 "hero.sub": "Jikji è un framework di agenti modulare sviluppato in Go — con un loop di agente deterministico, stato di orchestrazione durevole, coordinamento multimodello adattivo e governance integrata. Gli artefatti di rilascio sono compilati con CGO disabilitato; Linux amd64 è attualmente il target qualificato in modo nativo.",
 "cta.start": "Inizia subito",
 "story.tag": "Il nome",
 "story.h2": "Prende il nome dal primo libro al mondo stampato con caratteri mobili in metallo",
 "story.p1": "<b>Jikji</b> (직지심체요절) fu stampato in Corea nel 1377: è il più antico libro sopravvissuto stampato con caratteri mobili in metallo, decenni prima di Gutenberg. I caratteri mobili hanno cambiato l'editoria nello stesso modo in cui Jikji punta a cambiare gli agenti: <b>pezzi componibili, composti con precisione, che producono risultati affidabili su larga scala.</b>",
 "story.p2": "Ogni modulo porta un nome tipografico: la <b>foundry</b> fonde il runtime, il <b>typebackbone</b> dà volto ai modelli, i <b>sorts</b> sono gli strumenti, il <b>compositor</b> impagina le sessioni, la <b>forme</b> blocca il ciclo dell'agente e la <b>press</b> lo porta al mondo. Persino la porta predefinita è <span class=\"mono\">1377</span>.",
 "story.cap": "Jikjisimcheyojeol: il più antico libro esistente stampato con caratteri mobili in metallo. Memoria del Mondo UNESCO.",
 "nav.why": "Perché Jikji",
 "why.h2": "Cosa lo distingue dagli altri framework per agenti",
 "why.p": "La maggior parte dei framework per agenti sono librerie Python o Node.js/TypeScript incollate a un database vettoriale, con cicli opachi e una governance aggiunta in seguito. jikji è costruito come un'infrastruttura fin dal primo giorno.",
 "c1.h": "Rilasci Go senza CGO, confini dell'host espliciti",
 "c1.p": "Il rilascio di base non dipende da runtime Python o Node.js. Produciamo build incrociate per sei artefatti OS e architettura; la qualificazione nativa del rilascio copre attualmente Linux amd64. Gli strumenti opzionali e l'isolamento dell'host mantengono requisiti specifici della piattaforma.",
 "c1.more": "Scopri l'architettura →",
 "c2.h": "Un ciclo dell'agente deterministico e recuperabile",
 "c2.p": "Il ciclo <code>forme</code> modella ogni passo come azioni e osservazioni esplicite, con checkpoint e recupero integrati nel motore. Le esecuzioni degli agenti si possono rieseguire e verificare: niente più catene opache che svaniscono al primo crash.",
 "c2.more": "Dentro il ciclo →",
 "c3.h": "Orchestrazione adattiva tra più modelli",
 "c3.p": "Metti in campo uno swarm di modelli che discutono e si correggono, fai passare la sintesi al vaglio di un panel di verifica e lascia che il coordinatore <code>trinity</code> impari a quale modello affidare ogni turno: una policy evoluta, non uno schema fisso.",
 "c3.more": "Come funziona l'orchestrazione →",
 "c4.h": "Una memoria che impara, un contesto su misura",
 "c4.p": "Il piano di memoria <code>plate</code> estrae i fatti, li consolida in fasi di \"sogno\" in background e offre un recall ibrido. La compattazione del contesto e una scala di promozione dei modelli mantengono le esecuzioni lunghe dentro la finestra.",
 "c4.more": "Memoria &amp; dati →",
 "c5.h": "Governance integrata, non aggiunta dopo",
 "c5.p": "Multi-tenancy, chiavi API con scope, RBAC, una catena di filtri di policy dinamica con gate di approvazione, audit strutturato e mascheramento di PII e segreti: tutto nel cuore della piattaforma, con un vault per le credenziali e l'integrazione OAuth dei provider.",
 "c5.more": "Enterprise &amp; sicurezza →",
 "c6.h": "Protocolli aperti, nessun lock-in",
 "c6.p": "Espone un'API compatibile con OpenAI e parla MCP (server e client), ACP e A2A per la collaborazione tra agenti. Funziona con backend compatibili con OpenAI, Anthropic, Ollama e GLM/Z.AI.",
 "c6.more": "Protocolli &amp; interfacce →",
 "exp.tag": "Esplora la piattaforma",
 "exp.h2": "Sette piani, una pressa",
 "exp.p": "Ogni piano si occupa di una cosa sola, dietro un confine netto. Scegline uno e scendi nel dettaglio.",
 "exp.arch.h": "Architettura",
 "exp.arch.p": "Una tipografia di moduli componibili, configurazioni di deploy che vanno da un singolo processo a una griglia, storage basato su galley e i binari che la fanno girare.",
 "exp.more": "Continua a leggere →",
 "exp.loop.h": "Loop dell'agente",
 "exp.loop.p": "Il loop <code>forme</code> deterministico — checkpoint e ripresa, hook Lua, sintesi verifica-revisione, esecuzioni guidate da obiettivi e un harness che si migliora da solo.",
 "exp.more2": "Continua a leggere →",
 "exp.tools.h": "Strumenti",
 "exp.tools.p": "Un ampio catalogo integrato — file, shell, un browser che estrae il DOM, SQL, ontologia — eseguito in una sandbox, tramite MCP o su nodi remoti, oltre a funzioni Lua/Python come strumenti.",
 "exp.more7": "Scopri di più →",
 "exp.orch.h": "Orchestrazione",
 "exp.orch.p": "Swarm multi-modello, il coordinatore evoluto <code>trinity</code>, la delega ai sotto-agenti e la federazione A2A tra peer.",
 "exp.more3": "Continua a leggere →",
 "exp.mem.h": "Memoria &amp; dati",
 "exp.mem.p": "Memoria cognitiva con il sogno, recall ibrido, un knowledge graph, query ontologiche in SPARQL e backend SQLite/PostgreSQL/MySQL.",
 "exp.more4": "Continua a leggere →",
 "exp.onto.h": "Motore di ontologia",
 "exp.onto.p": "Un motore nativo che costruisce grafi di conoscenza da un corpus e li serve con SPARQL in-process: un'ontologia sui tuoi dati, senza alcun triple store esterno.",
 "exp.more6": "Scopri di più →",
 "exp.ent.h": "Enterprise &amp; sicurezza",
 "exp.ent.p": "Tenancy, RBAC e il piano delle policy, vault e OAuth, tracing con OpenTelemetry, limiti d'uso, mascheramento, difesa dalle injection e robustezza.",
 "exp.more5": "Continua a leggere →",
 "st.1": "target di build senza CGO",
 "st.3": "superfici di protocollo aperte",
 "st.4": "la porta predefinita, e l'anno",
 "proto.tag": "Interoperabilità",
 "proto.h2": "Parla tutti i protocolli che contano",
 "proto.openai": "<span class=\"mono\">/v1/chat/completions</span>, modelli, embedding, run e sessioni pronti all'uso: basta puntare i client esistenti su Jikji.",
 "proto.mcp": "Server e client Model Context Protocol via stdio: usa gli strumenti MCP o esponi Jikji come uno di essi.",
 "proto.acp": "Agent Communication Protocol via stdio per peer locali basati su processo.",
 "proto.a2a": "Collaborazione tra agenti: invio di task, delega e raccolta dei risultati da un agente all'altro.",
 "ops.h": "Strumenti per gli operatori",
 "ops.p": "<span class=\"mono\">jikjictl</span> gestisce credenziali e vault, RBAC, policy, query di audit, tracing, consumi e un marketplace, oltre a una dashboard web separata che non conserva mai le chiavi lato server.",
 "term.h": "Nativo da terminale",
 "term.p": "Chat TUI interattiva, modalità a prompt singolo, flussi di eventi JSONL per l'automazione e una modalità JSON-RPC in stile MCP: agenti che puoi mettere in pipe.",
 "test.h": "Testato come un'infrastruttura",
 "test.p": "Un gate <span class=\"mono\">make verify</span> deterministico più smoke test live controllati contro provider reali. Test di benchmark, fuzz, proprietà e concorrenza in tutto il codice.",
 "nav.start": "Inizia subito",
 "start.h2": "In funzione in meno di un minuto",
 "cm1": "avvia il server (porta predefinita 1377, sì, proprio quel 1377)",
 "cm2": "controlla il tuo ambiente locale",
 "cm3": "apri la chat TUI interattiva",
 "cm4": "oppure chiama l'API compatibile con OpenAI",
 "foot.tagline": "Caratteri mobili per l'era degli agenti.",
 "foot.author": "Realizzato da Jioh L. Jung.",
 "foot.explore": "Esplora",
 "foot.project": "Progetto",
 "nav.about": "Informazioni &amp; Contatti",
 "crumb.home": "Home",
 "arch.kicker": "Architettura",
 "arch.title": "Una tipografia di <span class=\"accent\">moduli componibili</span>",
 "arch.sub": "Ogni modulo si occupa di una cosa sola dietro un confine netto, utilizzabile prima in-process e progettato per spostarsi dietro HTTP o gRPC senza riscrivere la logica applicativa. Insieme compongono una piattaforma per agenti completa.",
 "arch.mods.tag": "I moduli",
 "arch.mods.p": "I nomi dei moduli seguono la visione tipografica di Jikji: ognuno prepara, autorizza, compone, stampa o distribuisce conoscenza.",
 "g.forme": "forme bloccata",
 "m.forme": "Ciclo dell'agente deterministico: delega, HITL, hook Lua, checkpoint, eventi di passo.",
 "g.trinity": "tre giudici",
 "m.trinity": "Coordinatore adattivo multi-modello: dibattito tra swarm, verifica-correggi, routing evoluto.",
 "g.compositor": "compositore",
 "m.compositor": "Orchestrazione delle sessioni, code, composizione dei flussi e memoria di collaborazione.",
 "g.dispatch": "smistamento del lavoro",
 "m.dispatch": "Scheduling per tenant/provider/modello, code limitate, retry con backoff, circuit breaker.",
 "g.type": "caratteri di metallo",
 "m.type": "Provider di inferenza su backend compatibili con OpenAI/Anthropic/Ollama/GLM, OAuth, consapevoli della finestra di contesto.",
 "g.sorts": "caratteri singoli",
 "m.sorts": "Esecuzione degli strumenti, integrazione MCP, runner, sandbox e nodi strumento remoti.",
 "g.press": "torchio da stampa",
 "m.press": "Ingresso HTTP: API compatibile con OpenAI, streaming SSE, webhook firmati, idempotenza.",
 "g.plate": "lastra stereotipica",
 "m.plate": "Memoria cognitiva: estrazione dei fatti, sogno, recall ibrido, compattazione.",
 "g.lexicon": "lessico",
 "m.lexicon": "Knowledge graph e ontologia: SPARQL, ri-ordinamento semantico, rilevamento delle contraddizioni.",
 "g.galley": "vassoio di galera",
 "m.galley": "Record e collegamenti condivisi su SQLite/PostgreSQL/MySQL per la collaborazione e uno stato che non si perde.",
 "g.imprimatur": "licenza di stampa",
 "m.imprimatur": "Tenancy, autenticazione tramite chiave API, scope/RBAC, ingresso delle credenziali, vault e OAuth.",
 "g.rubric": "rubrica di stile",
 "m.rubric": "Piano decisionale di autorizzazione: allow/deny/ask, valutazione delle policy, audit.",
 "g.proof": "bozza di stampa",
 "m.proof": "Rilevamento di PII e segreti, mascheramento reversibile, normalizzazione del testo sicura per l'audit.",
 "g.bookstore": "la libreria",
 "m.bookstore": "Marketplace di pacchetti e agenti: manifest, firma, installazione, riconciliazione.",
 "g.almanac": "almanacco",
 "m.almanac": "Scheduling deterministico: cron, intervalli, batch e lavori di manutenzione.",
 "g.foundry": "fonderia di caratteri",
 "m.foundry": "Bootstrap, configurazione, controlli diagnostici e controllo dell'orchestrazione.",
 "arch.mods.note": "Altri moduli completano la piattaforma — <span class=\"mono\">screen</span> (la catena dinamica di filtri di policy), <span class=\"mono\">relay</span> (tunnel TLS verso i nodi strumento remoti), <span class=\"mono\">usagelimit</span> e <span class=\"mono\">observability</span> — trattati nella pagina Enterprise.",
 "arch.prov.tag": "typebackbone — Provider &amp; Modelli",
 "arch.prov.h2": "Collega qualsiasi modello e instradalo a modo tuo",
 "arch.prov.p": "La struttura portante <span class=\"mono\">typebackbone</span> dialoga con molte famiglie di provider dietro un'unica interfaccia, così puoi combinare i modelli liberamente e cambiarli senza toccare i tuoi agenti.",
 "arch.prov.1.h": "Molte famiglie di provider",
 "arch.prov.1.p": "Compatibile con OpenAI, Anthropic Messages, Ollama Cloud, GLM / Z.AI, xAI Grok e OpenAI Codex — più un provider echo integrato per il lavoro offline. Categorie Chat, embedding e rerank, e qualsiasi endpoint compatibile con OpenAI a cui lo punti.",
 "arch.prov.2.h": "OAuth o chiavi, decidi tu",
 "arch.prov.2.p": "Le credenziali provengono da variabili d'ambiente, dal vault o dall'accesso tramite dispositivo OAuth (Codex, Grok) con aggiornamento automatico dei token. Una chiave in stile <code>oauth:grok</code> viene risolta al momento della richiesta, e le chiavi inline vengono oscurate nell'esportazione della configurazione.",
 "arch.prov.3.h": "Instradamento intelligente",
 "arch.prov.3.p": "Alias dei modelli, candidati provider ordinati con failover, rotazione multi-chiave e instradamento sticky consapevole della cache mantengono la selezione del provider nella configurazione. L'instradamento per gruppi di modelli specifici per ruolo resta fuori dal contratto runtime dichiarato finché il relativo percorso di dispatch in produzione non sarà completamente collegato.",
 "arch.prov.4.h": "Runtime consapevole del provider",
 "arch.prov.4.p": "La consapevolezza della finestra di contesto per ciascun provider guida la scala di promozione dei modelli, la cache dei prompt nativa del provider viene usata dove disponibile, e i limiti d'uso esterni sono tracciati per provider.",
 "arch.prov.cap": "Combina i provider e assegna loro degli alias — OAuth, chiavi e il tuo endpoint fianco a fianco:",
 "arch.dep.tag": "Configurazioni di deploy",
 "arch.dep.h2": "Indipendente dalla scala — dal portatile al data center, da locale a remoto, da uno a molti",
 "arch.dep.p": "La forma del deployment cambia tramite la configurazione — per scala, posizione e numero di istanze. Avvia il runtime qualificato in un processo, separa i piani in servizi, sposta l'esecuzione degli strumenti su nodi remoti, quindi esegui molte istanze dietro un database condiviso — il tutto senza modificare i tuoi agenti.",
 "arch.dep.1.h": "Un solo processo, prima il locale",
 "arch.dep.1.p": "Un deployment compatto integra SQLite per uno stato durevole. Il runtime Linux di base si avvia da un file di configurazione su un portatile o dispositivo edge; i profili distribuiti aggiungono solo i servizi richiesti dalla loro topologia.",
 "arch.dep.2.h": "Diviso in servizi",
 "arch.dep.2.p": "Esegui l'ingresso <code>press</code>, il controller <code>dispatch</code> e i nodi degli strumenti come processi separati. gRPC collega il controller ai nodi degli strumenti remoti (con TLS opzionale), mentre il controller dispatch coordina i worker tramite il database condiviso. L'esecuzione degli strumenti passa ai worker <code>jikji-tool-node</code> dietro un tunnel <code>jikji-relay</code>.",
 "arch.dep.3.h": "Cluster multi-nodo",
 "arch.dep.3.p": "Punta <code>galley</code> su un PostgreSQL o MySQL condiviso per l'alta disponibilità multi-nodo, coordina dispatch tramite il database condiviso con lease distribuiti, circuit breaker per nodo e failover, ed esporta tracce e metriche verso il tuo stack.",
 "arch.dep.note": "<b>Profili</b> — preset di bootstrap (<span class=\"mono\">desktop</span>, <span class=\"mono\">edge</span>, <span class=\"mono\">controller</span>, <span class=\"mono\">all</span>) scelgono quali piani esegue un nodo, così la stessa immagine ricopre qualsiasi ruolo nel cluster.",
 "arch.dep.cap": "L'alta affidabilità multi-nodo è una modifica della configurazione, non una riscrittura — collega gli artefatti di servizio qualificati a un database condiviso:",
 "arch.dep.free.h": "Libero su ogni asse.",
 "arch.dep.free.scale.l": "Senza limiti di scala",
 "arch.dep.free.scale.d": "dal laptop al data center.",
 "arch.dep.free.loc.l": "Senza vincoli di posizione",
 "arch.dep.free.loc.d": "dall'esecuzione locale fino ai nodi remoti.",
 "arch.dep.free.net.l": "Senza barriere di rete",
 "arch.dep.free.net.d": "un tunnel relay TLS raggiunge i nodi attraverso le reti, dietro un NAT o un firewall, on-premises o in qualsiasi cloud — così ambienti che altrimenti non potrebbero vedersi si uniscono in un unico tessuto.",
 "arch.dep.free.os.l": "Sei target di build senza CGO",
 "arch.dep.free.os.d": "Il gate di rilascio locale esegue la compilazione incrociata degli artefatti Linux, macOS e Windows per amd64 e arm64 con CGO disabilitato. Linux amd64 è qualificato in modo nativo per il rilascio; gli altri cinque target sono solo convalidati tramite compilazione e richiedono test dell'operatore. I controlli sandbox di Linux non si trasferiscono e BSD non è un target di build o test supportato.",
 "arch.dep.free.inst.l": "Senza vincoli di istanza",
 "arch.dep.free.inst.d": "un processo o molti dietro un database condiviso, con elezione del leader in HA.",
 "arch.dep.free.foot": "La stessa famiglia di release e gli stessi contratti degli agenti coprono l'intera matrice; configurazione e qualificazione dell'host di destinazione determinano le funzionalità disponibili.",
 "arch.store.tag": "Storage &amp; binari",
 "arch.store.h2": "Stato basato su galley, cinque binari",
 "arch.store.p": "<b>galley</b> è lo spazio di lavoro condiviso per la collaborazione: un unico schema, con migrazioni esplicite, che fa da base a memoria, record di dispatch, marketplace, task A2A, credenziali e log di audit. Gira su SQLite integrato per impostazione predefinita e su PostgreSQL o MySQL per i deploy multi-nodo, con DDL consapevole del dialetto e un gestore di lease distribuito per il recupero dei task.",
 "arch.bin.1.k": "jikji",
 "arch.bin.1.v": "Il server runtime principale: ciclo dell'agente, API compatibile con OpenAI, dispatch, canali e dashboard, selezionati dal profilo.",
 "arch.bin.2.k": "jikjictl",
 "arch.bin.2.v": "La CLI per gli operatori: salute, modelli, credenziali e vault, RBAC, policy, filtri, OAuth dei provider, consumi, audit e marketplace.",
 "arch.bin.3.k": "jikjicode",
 "arch.bin.3.v": "Una CLI di coding autonoma che pilota strumenti locali in sandbox contro un server di modelli remoto compatibile con OpenAI.",
 "arch.bin.4.k": "jikji-relay",
 "arch.bin.4.v": "Un proxy di tunneling TLS (TLS 1.3) che collega un controller ai nodi strumento remoti attraverso le reti.",
 "arch.bin.5.k": "jikji-tool-node",
 "arch.bin.5.v": "Un esecutore remoto di strumenti che si registra presso il controller, esegue gli strumenti tramite runner governati e invia heartbeat sul proprio stato. L'isolamento a livello di sistema operativo segue la matrice di supporto dell'host di destinazione.",
 "arch.proto.h2": "Interfacce a protocolli aperti",
 "arch.proto.p": "Jikji è pensato per inserirsi in ciò che già usi: punta su di esso i client OpenAI esistenti, fai da ponte agli strumenti MCP in entrambe le direzioni o federa gli agenti via A2A.",
 "arch.proto.openai": "<span class=\"mono\">/v1/chat/completions</span>, <span class=\"mono\">/v1/models</span>, <span class=\"mono\">/v1/embeddings</span>, più run e sessioni native per gli agenti.",
 "arch.proto.mcp": "Server e client Model Context Protocol via stdio: usa gli strumenti MCP o esponi Jikji come uno di essi.",
 "arch.proto.acp": "Agent Communication Protocol via stdio per peer locali basati su processo.",
 "arch.proto.a2a": "Invio e registro dei task tra agenti tramite gRPC, oltre a un canale gRPC verso i nodi degli strumenti remoti. Il lavoro multi-nodo viene coordinato tramite il database galley condiviso con lease distribuiti.",
 "arch.routes.1.k": "Chat &amp; modelli",
 "arch.routes.2.k": "Run degli agenti",
 "arch.routes.3.k": "Salute &amp; operatività",
 "arch.routes.4.k": "Amministrazione",
 "arch.routes.4.note": "(riservato agli operatori)",
 "arch.perf.tag": "Prestazioni &amp; efficienza",
 "arch.perf.h2": "Molte sessioni, ingombro ridotto",
 "arch.perf.p": "Un core Go compilato evita un runtime del linguaggio per ogni sessione, mentre code limitate, cache e composizione in-process riducono l'overhead di coordinamento. Misura la release esatta con i tuoi modelli, strumenti e profilo di concorrenza: la latenza del provider e la forma del carico dominano le prestazioni end-to-end.",
 "arch.perf.1.h": "Concorrenza senza zavorra",
 "arch.perf.1.p": "Le goroutine di Go multiplexano un numero limitato di sessioni simultanee senza un interprete per sessione. La composizione in-process mantiene il coordinamento locale sui confini delle chiamate di funzione; i piani remoti restano salti di rete espliciti.",
 "arch.perf.2.h": "Veloce per costruzione",
 "arch.perf.2.p": "Il routing sticky attento alla cache, il caching dei prompt nativo del provider e una cache semantica delle risposte tagliano le chiamate al modello ridondanti; circuit breaker e code limitate impediscono che un upstream lento trascini giù tutto il resto.",
 "arch.perf.3.h": "Ingombro ridotto",
 "arch.perf.3.p": "Gli artefatti di rilascio senza CGO, SQLite integrato e cache limitate mantengono compatto il deployment di base. La capacità e il comportamento dell'host devono comunque essere qualificati usando le dimensioni reali del contesto, i moduli abilitati, la concorrenza del provider e il sistema operativo target.",
 "arch.perf.note": "<b>Prima le prove, poi gli aggettivi.</b> Conserva il rapporto di verifica della release e ripeti le prove di carico, ripristino, sandbox e database sul sistema operativo e sulla topologia esatti che intendi utilizzare.",
 "pn.back": "← Indietro",
 "pn.home": "Panoramica",
 "pn.next": "Avanti →",
 "loop.kicker": "Il motore",
 "loop.title": "Un ciclo dell'agente deterministico e <span class=\"accent\">recuperabile</span>",
 "loop.sub": "Il motore <span class=\"mono\">forme</span> modella ogni passo come un'azione e un'osservazione esplicite. Le esecuzioni salvano un checkpoint dopo ogni passo, riprendono esattamente da dove si erano fermate e non perdono mai lavoro in silenzio: così il ciclo dell'agente si comporta come una transazione, non come una scatola nera.",
 "loop.l.tag": "Il ciclo",
 "loop.l.h2": "Pianifica → agisci → osserva → integra, e ripeti",
 "loop.l.p": "Un pianificatore propone l'azione successiva; il motore la convalida, la esegue, ne integra l'osservazione nello stato ed emette un evento di passo. Ogni tipo di azione è esplicito e limitato.",
 "loop.dia.1": "proponi l'azione successiva",
 "loop.dia.2": "convalida ed esegui",
 "loop.dia.3": "integra un'osservazione tipizzata",
 "loop.dia.4": "salva ed emetti un evento di passo",
 "loop.dia.back": "↻ ripeti fino a <span class=\"mono\">respond</span>, <span class=\"mono\">stop</span> o all'esaurimento del budget di passi",
 "loop.act.label": "Tipi di azione<span class=\"mono\">forme.Action</span>",
 "loop.act.p": "Ogni turno si risolve in esattamente un'azione, convalidata prima dell'esecuzione:",
 "loop.act.1": "<code>think</code> — registra il ragionamento senza alcun effetto esterno.",
 "loop.act.2": "<code>tool</code> — chiama uno strumento, in linea per uno solo o in coda per l'esecuzione in parallelo.",
 "loop.act.3": "<code>respond</code> / <code>stop</code> — emette la risposta finale e chiude l'esecuzione.",
 "loop.act.4": "<code>delegate</code> — affida un sotto-task a un agente figlio e ne raccoglie il risultato.",
 "loop.act.5": "<code>wait</code> — mette in pausa l'esecuzione finché un evento esterno o un timeout la risveglia.",
 "loop.act.note": "Il budget di passi per turno segue il limite dichiarato dal modello scelto (predefinito locale 1024, protezione assoluta 4096; limite remoto 1024), così ogni ciclo termina senza imporre lo stesso orizzonte fisso a tutti i modelli.",
 "loop.obs.label": "Osservazioni<span class=\"mono\">categorizzate</span>",
 "loop.obs.p": "I risultati vengono reintegrati come osservazioni tipizzate, così la traccia è leggibile dalle macchine e non testo libero:",
 "loop.obs.1": "osservazioni di pensiero, risultato dello strumento ed errore",
 "loop.obs.2": "osservazioni di policy quando un gate concede, nega o chiede",
 "loop.obs.3": "osservazioni di attesa quando l'esecuzione va in pausa",
 "loop.obs.4": "osservazioni di raccolta quando il risultato di un sotto-agente viene reintegrato nella sintesi",
 "loop.ckpt.label": "Checkpoint &amp; ripresa<span class=\"mono\">prove verificate</span>",
 "loop.ckpt.p": "Un checkpoint registra tenant, frontiera dei passi, id dell'ultima chiamata a strumento ed eventuale stato di attesa. La ripresa convalida queste correlazioni prima di ripristinare i passi completati; una chiamata completata con prove durevoli corrispondenti non viene rieseguita, mentre prove non valide o discordanti causano una chiusura sicura.",
 "loop.ckpt.1": "si mette in pausa su <code>wait</code>, poi si risveglia al completamento di un figlio o a un timeout",
 "loop.ckpt.2": "a prova di crash: un'esecuzione sopravvive ai riavvii del processo e riprende da dove si era interrotta",
 "loop.ckpt.3": "ri-eseguibile e verificabile dall'inizio alla fine",
 "loop.lua.label": "Hook Lua &amp; inquiry<span class=\"mono\">scripting fidato</span>",
 "loop.lua.p": "Hook Lua fidati iniettano piani e indicazioni nel ciclo, con binding per inquiry, dibattito, costo, budget e il lexicon. Il sistema inquiry raccoglie risposte strutturate tramite questionari persistenti, basati su pausa e ripresa: l'esecuzione si blocca su una domanda e prosegue una volta ricevuta la risposta.",
 "loop.verify.label": "Sintesi verifica-correggi<span class=\"mono\">con gate</span>",
 "loop.verify.p": "Una risposta finale può passare al vaglio di un panel di verifica: se la maggioranza vota CORREGGI, il ciclo rifà la sintesi tenendo conto della critica, entro un numero limitato di round. L'output grezzo degli strumenti può essere impedito di scavalcare la risposta, così i modelli ragionano sui risultati invece di restituire dati non elaborati.",
 "loop.ctx.label": "Contesto &amp; budget<span class=\"mono\">resta nella finestra</span>",
 "loop.ctx.p": "Una scala di promozione dei modelli riprova un turno in overflow sulla finestra di contesto successiva più grande e mantiene la promozione. Indicazioni dinamiche per turno trasmettono la guida in avanti, e un budget di esecuzione (token massimi, tempo massimo) si ferma con grazia, producendo una risposta finale sintetizzata invece di un taglio netto.",
 "loop.goal.label": "Esecuzioni guidate da obiettivi<span class=\"mono\">set · evaluate · report</span>",
 "loop.goal.p": "Oltre il singolo prompt, un'esecuzione può perseguire un <b>obiettivo</b> duraturo. Un ciclo guidato da obiettivi porta avanti il lavoro lungo le iterazioni — ognuna costruisce su tutto ciò che è stato prodotto finora — e termina quando il modello segnala che l'obiettivo è raggiunto o si tocca un limite.",
 "loop.goal.1": "definire un obiettivo, arricchirlo e tradurlo in lavoro concreto",
 "loop.goal.2": "valutare i progressi e riferire lo stato rispetto all'obiettivo",
 "loop.goal.3": "persiste tra le sessioni: un obiettivo sopravvive a qualunque esecuzione",
 "loop.human.label": "Umano nel &amp; sul loop<span class=\"mono\">approva · supervisiona</span>",
 "loop.human.in": "<b>Umano nel loop («human in the loop»).</b> I gate di approvazione e le richieste mettono in pausa l'esecuzione in attesa di una decisione: l'agente si blocca finché una persona non approva, rifiuta o risponde, poi riprende esattamente dal checkpoint in cui si era fermato. Nulla di rischioso accade alle tue spalle.",
 "loop.human.on": "<b>Umano sul loop («human on the loop»).</b> Per impostazione predefinita, un'esecuzione trasmette ogni passaggio in tempo reale, così un operatore osserva dal vivo e interviene solo quando serve: cambia la policy di uno strumento su <code>ask</code>, rispondi a una richiesta, annulla un'esecuzione o riporta una sessione a uno snapshot integro. Supervisione senza dover stare col fiato sul collo.",
 "loop.cfg.cap": "Modella il ciclo con un pianificatore, profili con nome e hook Lua:",
 "loop.trace.cap": "Ogni passo viene emesso come evento JSONL: ri-eseguibile e verificabile:",
 "loop.self.tag": "Auto-migliorante &amp; estensibile",
 "loop.self.h2": "Un loop che riscrive il proprio manuale",
 "loop.self.p": "Il harness non è fissato in fase di compilazione. Impara procedure riutilizzabili, si rimodella tramite Lua, indaga ciò che non conosce e adotta nuovi strumenti — il tutto senza mai fare il fork del motore.",
 "loop.self.1.h": "Impara competenze riutilizzabili",
 "loop.self.1.p": "Dopo un'esecuzione consistente, un revisore post-esecuzione limitato distilla ciò che l'agente ha capito in una <b>competenza</b> duratura — così la prossima esecuzione parte avvantaggiata. Le competenze si caricano su richiesta con <code>skill.load</code> e si agganciano a un profilo o corrispondono all'obiettivo per parola chiave.",
 "loop.self.2.h": "Rimodella il loop con Lua",
 "loop.self.2.p": "Hook Lua affidabili su <code>plan</code>, <code>before_tool</code> e <code>after_tool</code> consentono a te — e all'agente stesso — di cambiare a runtime il modo in cui il loop pianifica e richiama gli strumenti, il tutto entro un rigido budget di tempo e di istruzioni.",
 "loop.self.3.h": "Ricerca con affermazioni verificate",
 "loop.self.3.p": "Il meccanismo di ricerca pianifica un'indagine, recupera fonti ed esegue ricerche sul web — e sottopone i propri risultati a un'asticella scientifica: la previsione viene <b>preregistrata</b> prima che esista qualsiasi evidenza, il protocollo sperimentale viene congelato e l'affermazione è confermata solo da esecuzioni reali, ripetute e analizzate dalla macchina. Metriche di qualità meccaniche (nessun LLM che giudica sé stesso) guidano poi un ciclo di revisione limitato. Lo stesso meccanismo sostiene i gate di deployment e le guardie di regressione, non solo i paper.",
 "loop.self.4.h": "Estensibile per progettazione",
 "loop.self.4.p": "Competenze, hook Lua, strumenti MCP e installazioni firmate dal marketplace estendono tutti lo stesso loop. Ogni nuova capacità si aggiunge attorno al motore, mai riscrivendolo.",
 "loop.lh.tag": "Il lungo orizzonte",
 "loop.lh.h2": "Pronto per il lavoro agentico a lungo orizzonte",
 "loop.lh.p": "I veri workflow agentici non finiscono in un solo respiro — girano per ore, attendono il mondo esterno e si estendono su più giorni. Ogni primitiva di questa pagina esiste perché un'esecuzione possa arrivare fino in fondo senza perdere il filo.",
 "loop.lh.1.h": "Uno stato che sopravvive a un riavvio",
 "loop.lh.1.p": "I checkpoint durevoli consentono a un'esecuzione convalidata di riprendere dopo un riavvio o un nuovo deployment. Le protezioni dal replay coprono le chiamate completate con prove corrispondenti; gli effetti collaterali esterni richiedono comunque idempotenza downstream oltre un confine di crash ambiguo.",
 "loop.lh.2.h": "Metti in pausa ora, continua dopo",
 "loop.lh.2.p": "Un'esecuzione può attendere un evento esterno, un'approvazione o un agente figlio e risvegliarsi ore o giorni dopo — nulla deve restare bloccato in memoria per l'intera durata.",
 "loop.lh.3.h": "Obiettivi che sopravvivono a un'esecuzione",
 "loop.lh.3.p": "Un obiettivo durevole viene portato avanti attraverso molte esecuzioni e sessioni finché non viene raggiunto — il lavoro di lunga durata ha memoria della propria intenzione, non solo del suo ultimo turno.",
 "loop.lh.4.h": "Coerente per tutta la distanza",
 "loop.lh.4.p": "La compattazione del contesto e la scala di promozione dei modelli mantengono le esecuzioni molto lunghe dentro la finestra, e lo scheduler <code>almanac</code> guida il lavoro ricorrente — così un workflow può estendersi su più giorni e mantenere comunque il filo.",
 "loop.lh.5.h": "Ogni turno passa da un filtro",
 "loop.lh.5.p": "Prima che un turno pianificato o autonomo consumi anche solo un po' di calcolo, il loop lo classifica — <code>deliver</code>, <code>ask</code> a un umano, <code>wait</code> in attesa di prove, <code>self-repair</code> o restare <code>quiet</code> — attraverso uno stack di filtri a precedenza fissa, così che un blocco di salute o un'approvazione in sospeso abbiano sempre la priorità sul budget residuo. Nessuna esecuzione brucia token solo perché può.",
 "loop.lh.6.h": "Obiettivi con un traguardo",
 "loop.lh.6.p": "Gli obiettivi sono strutturati e gerarchici — i sotto-obiettivi confluiscono nel loro obiettivo padre — e portano KPI dietro un cancello di accettazione meccanico con provenienza delle prove. Un'esecuzione lunga è giudicata completata in base a prove misurabili, non sulla parola del modello.",
 "orch.kicker": "Tanti modelli, una sola press",
 "orch.title": "Metti <span class=\"accent\">tanti modelli</span> all'unisono",
 "orch.sub": "Un modello è un singolo sort; l'orchestrazione è la pagina composta. Jikji esegue swarm che discutono e si correggono, un coordinatore evoluto che impara a quale modello affidare ogni turno e una delega che distribuisce il lavoro a sotto-agenti e peer.",
 "orch.sw.tag": "Multi-modello",
 "orch.sw.h2": "Swarm che discutono, poi una sintesi con gate",
 "orch.sw.p": "Più modelli rispondono alla stessa domanda, si criticano a vicenda lungo i round e un sintetizzatore scrive la risposta finale, con verifica opzionale prima della consegna.",
 "orch.sw.1.h": "Discuti &amp; sintetizza",
 "orch.sw.1.p": "I partecipanti aprono ciascuno con una risposta, poi svolgono round limitati di critica e correzione. Un sintetizzatore compone il risultato; con la verifica attiva, un panel giudica ACCETTA o CORREGGI e rifà la sintesi su una maggioranza CORREGGI.",
 "orch.sw.2.h": "Itera fino a uno standard",
 "orch.sw.2.p": "Guida un singolo modello attraverso ripetuti round di miglioramento e controllo finché non raggiunge uno standard di qualità o un limite di passi: utile per stesura, refactoring e autocorrezione.",
 "orch.sw.3.h": "Confronta i candidati",
 "orch.sw.3.p": "Esegui lo stesso task su più modelli o configurazioni e confronta i candidati fianco a fianco, così le scelte di routing e di provider poggiano su dati concreti, non su congetture.",
 "orch.sw.cap": "Chiama uno swarm come strumento: i partecipanti discutono, poi un panel di verifica filtra il risultato:",
 "orch.tr.tag": "trinity — il coordinatore",
 "orch.tr.h2": "Un coordinatore che impara il routing",
 "orch.tr.p": "La maggior parte dei sistemi \"multi-agente\" segue uno script fisso. Il coordinatore <span class=\"mono\">trinity</span> esegue una policy appresa sullo stato in tempo reale di un'esecuzione: quale modello, in quale ruolo, in questo turno. È una policy che fai evolvere e abiliti; per impostazione predefinita, l'ensemble usa il variegato panel vincolato a verificatore.",
 "orch.tr.role.label": "Ciclo a tre ruoli<span class=\"mono\">thinker · worker · verifier</span>",
 "orch.tr.role.p": "Un pool eterogeneo di agenti viene guidato attraverso un ciclo thinker / worker / verifier. A ogni turno il coordinatore sceglie quale agente agisce e in quale ruolo, optando per il più adatto allo stato attuale del task.",
 "orch.tr.route.label": "Routing adattivo<span class=\"mono\">policy evoluta</span>",
 "orch.tr.route.p": "La policy di selezione si basa su caratteristiche osservabili — indice del turno, presenza o meno di un piano, ultimo verdetto, numero di correzioni e segnali del task — ed è addestrata con una strategia evolutiva CMA-ES separabile, poi salvata e servita quando la abiliti. Il risultato è un routing adattivo, non uno schema cablato a mano.",
 "orch.tr.ens.label": "Ensemble &amp; verifica-correggi<span class=\"mono\">gate di qualità</span>",
 "orch.tr.ens.p": "Il coordinamento si combina con il gate verifica-correggi del ciclo e con la sintesi a ensemble, così più modelli contribuiscono e un verificatore tiene alto lo standard prima che una risposta venga restituita.",
 "orch.tr.oracle.label": "Controllo di deriva<span class=\"mono\">oracle</span>",
 "orch.tr.oracle.p": "Uno strumento <code>trinity.oracle</code> esegue un controllo di coerenza della deriva — verifica se un'esecuzione è rimasta coerente con il suo obiettivo, il suo piano e le sue prove. È un auto-audit che qualsiasi agente può invocare per intercettare un'esecuzione che ha silenziosamente deviato dal compito.",
 "orch.tr.cap": "Le strategie di routing sono configurabili per ogni gruppo di modelli:",
 "orch.del.tag": "Delega &amp; federazione",
 "orch.del.h2": "Dai sotto-agenti ai peer in rete",
 "orch.del.1.h": "Delega ai sotto-agenti",
 "orch.del.1.p": "Un'azione <code>delegate</code> affida un sotto-compito delimitato a un agente figlio. Gli spawn sono idempotenti — indicizzati da <code>(parent, request_key)</code> in modo che un nuovo tentativo non produca mai un duplicato — e portano un ruolo limitato al compito. Un supervisore tiene traccia dei figli, raccoglie i loro risultati nella traccia del padre, e una scorecard verifica gli esiti.",
 "orch.del.2.h": "Federazione A2A",
 "orch.del.2.p": "Il protocollo agente-a-agente copre create / send / get / cancel delle attività più un registro agenti con heartbeat. Usalo per peer esplicitamente configurati e con ambito tenant; la federazione cross-tenant non è presentata come un confine di sicurezza supportato.",
 "orch.del.3.h": "Memoria di collaborazione",
 "orch.del.3.p": "Lo spazio di lavoro <code>galley</code> conserva record condivisi, task delegati e l'intento delle conversazioni tra una sessione e l'altra, con un gestore di lease basato su TTL che rivendica i task e recupera quelli orfani.",
 "orch.del.4.h": "Protocolli aperti per agenti",
 "orch.del.4.p": "Oltre ad A2A, Jikji parla MCP e ACP via stdio per i peer locali e coordina il dispatch multi-nodo via gRPC, così l'orchestrazione non resta mai legata a un solo runtime.",
 "orch.del.5.h": "I piani come grafi di dipendenze",
 "orch.del.5.p": "<code>taskgraph.run</code> esegue un piano intero: i task con archi <code>depends_on</code> girano ciascuno come sub-agente durevole una volta completate le loro dipendenze. I task della stessa ondata girano in parallelo — a meno che non tocchino lo stesso file, nel qual caso vengono serializzati — e il grafo viene validato in anticipo, quindi un ciclo viene rifiutato prima che parta qualsiasi cosa.",
 "orch.svc.tag": "Una sessione come servizio",
 "orch.svc.h2": "Trasforma una sessione in un servizio — spesso senza scrivere codice",
 "orch.svc.p": "Ciò che costruisci in una chat è il prodotto. jikji può servire una sessione pronta come modello, filtrarne l'output con Lua, esporre la tua ontologia ed eseguirla secondo una pianificazione — così un nuovo agente di servizio è configurazione, non una base di codice.",
 "orch.svc.1.h": "Una sessione diventa un modello",
 "orch.svc.1.p": "Registra una sessione pronta — il suo contesto catturato come prefisso in prompt-cache — e comparirà in <code>/v1/models</code>, richiamabile subito come id di modello. Il costoso priming diventa un cache hit a ogni chiamata, così il contesto si conserva a basso costo. Nessun codice nuovo, nessun nuovo deploy.",
 "orch.svc.2.h": "Filtra le risposte con Lua",
 "orch.svc.2.p": "Un filtro di contenuti Lua a sicurezza intrinseca esamina e rimodella ciò che passa — oscura, riscrive o blocca una risposta prima che raggiunga il chiamante — con HTTP opzionale e su lista di autorizzazioni per l'arricchimento.",
 "orch.svc.3.h": "Servi l'ontologia",
 "orch.svc.3.p": "Esponi il knowledge graph nativo come servizio interrogabile, in modo che SPARQL e la ricerca semantica siano a disposizione di tutti i chiamanti — non solo dell'agente che l'ha costruito.",
 "orch.svc.4.h": "Eseguila secondo una pianificazione",
 "orch.svc.4.p": "Lo scheduler <code>almanac</code> gestisce job cron e a intervallo — un aggiornamento notturno dell'ontologia, un report periodico, un controllo ricorrente — senza alcuno scheduler esterno da collegare.",
 "orch.svc.5.h": "Raggiungi gli utenti sui loro canali",
 "orch.svc.5.p": "Offri lo stesso agente sui canali di messaggistica: un messaggio in arrivo diventa un'esecuzione e la risposta riparte subito, con ambiti degli strumenti per ogni chat, memoria persistente per ogni chat, allowlist e limiti di frequenza. Un adattatore Telegram è disponibile già oggi, e l'interfaccia degli adattatori è progettata per andare oltre — Slack e non solo — insieme a webhook in entrata firmati.",
 "orch.svc.6.h": "Gli agenti pubblicano le proprie superfici",
 "orch.svc.6.p": "Un agente può pubblicare una UI live con <code>ui.render</code> — una tabella o un grafico dichiarativi vengono serviti subito (rendering lato server, nessuno script dell'agente viene eseguito) — oppure un'API su <code>/svc/{tenant}/{name}</code> con <code>service.publish</code>: un corpo statico, un handler Lua in sandbox, o un template di obiettivo in cui <b>ogni richiesta guida un'esecuzione durevole dell'agente</b>. Tutto ciò che esegue codice viene pubblicato in stato pendente e viene servito solo dopo l'approvazione di un operatore.",
 "orch.xr.tag": "Multi-regione &amp; multi-OS",
 "orch.xr.h2": "Strumenti senza confini",
 "orch.xr.p": "Una chiamata a uno strumento non deve per forza eseguirsi dove l'agente sta ragionando. Gli strumenti vengono eseguiti su nodi remoti scelti per capacità e posizionamento, raggiungibili tramite tunnel relay — così una singola esecuzione può estendersi tra macchine, cloud, regioni e sistemi operativi, con un catalogo condiviso durevole, circuit breaker per nodo e failover.",
 "orch.xr.eg": "<b>Un'esecuzione, host instradati per capacità.</b> Instrada il lavoro registrato in base alle capacità e alle etichette di posizionamento. Linux amd64 è il target qualificato in modo nativo; gli artefatti macOS e Windows sono convalidati tramite compilazione incrociata e devono essere qualificati dall'operatore prima dell'uso. Ogni runner mantiene il confine di isolamento del proprio host e BSD non è supportato.",
 "mem.kicker": "plate · lexicon · galley",
 "mem.title": "Una memoria che <span class=\"accent\">impara</span>, un contesto su misura",
 "mem.sub": "Il piano di memoria <span class=\"mono\">plate</span> estrae i fatti, li consolida nei momenti di inattività e offre un recall ibrido, mentre la compattazione del contesto e una scala di promozione mantengono le esecuzioni lunghe dentro la finestra. La conoscenza vive in un grafo che puoi interrogare in SPARQL, sul database che già usi.",
 "mem.cm.tag": "plate — memoria cognitiva",
 "mem.cm.h2": "Estrai, consolida, recupera",
 "mem.cm.store.label": "Store a livelli<span class=\"mono\">un solo piano</span>",
 "mem.cm.store.p": "La memoria non è un unico contenitore. La plate tiene la memoria di lavoro dei turni recenti, embedding vettoriali densi, triple semantiche estratte, entità risolte e un livello ontologico, il tutto interrogabile insieme.",
 "mem.cm.recall.label": "Recall ibrido<span class=\"mono\">BM25 + vettori</span>",
 "mem.cm.recall.p": "Il recall fonde la ricerca per parole chiave (BM25) e quella vettoriale semantica, partizionate per tenant e attore così la memoria non trapela mai tra soggetti diversi. Quando l'estensione è disponibile si usa un backend nativo <code>sqlite-vec</code>.",
 "mem.cm.dream.label": "Sogno<span class=\"mono\">consolidamento in background</span>",
 "mem.cm.dream.p": "Fasi pianificate in background consolidano la memoria di lavoro nello storage a lungo termine, valutando i fatti per importanza e attualità, rilevando contraddizioni tra sessioni e segnalando come obsoleti i fatti man mano che le loro fonti cambiano.",
 "mem.ctx.tag": "Ottimizzazione di contesto &amp; token",
 "mem.ctx.h2": "Fai entrare di più in ogni finestra",
 "mem.ctx.p": "Le esecuzioni lunghe sfondano le finestre di contesto e bruciano token. Jikji tratta la finestra come una risorsa da gestire, non come un muro contro cui sbattere.",
 "mem.ctx.1.h": "Compattazione del contesto",
 "mem.ctx.1.p": "I turni più vecchi e meno importanti vengono eliminati in base a un punteggio di importanza prima che la finestra trabocchi, così il thread conserva ciò che conta mentre il conteggio dei token resta limitato — la compattazione scatta quando un'esecuzione si avvicina al suo limite.",
 "mem.ctx.2.h": "Scala di promozione dei modelli",
 "mem.ctx.2.p": "Quando un turno andrebbe in overflow, l'esecuzione riprova sulla finestra di contesto successiva più grande e mantiene la promozione, invece di fallire o troncare il prompt in silenzio.",
 "mem.ctx.3.h": "Caching su hot path &amp; dei prompt",
 "mem.ctx.3.p": "Un memo in-process limitato mette in cache i ricalcoli più frequenti, una cache con namespace per tenant serve i risultati tra una richiesta e l'altra e, dove disponibile, si usa il prompt caching nativo del provider (cache-control, chiavi di cache).",
 "mem.ctx.4.h": "Un percorso di embedding separato",
 "mem.ctx.4.p": "Il recupero e il riordino vengono eseguiti su un percorso di embedding dedicato — scegli il modello che preferisci (Jina, OpenAI o Ollama), indipendente dal provider di chat così da poter ottimizzare la ricerca a parte. È facoltativo: se non imposti alcun provider di embedding, il sistema funziona solo con grafo e parole chiave.",
 "mem.ctx.cap": "Il caching semantico delle risposte riusa le risposte per significato, non per testo esatto:",
 "mem.kg.tag": "lexicon — conoscenza &amp; ontologia",
 "mem.kg.h2": "Un knowledge graph che puoi interrogare",
 "mem.kg.build.label": "Costruito dai documenti<span class=\"mono\">lexicon</span>",
 "mem.kg.build.p": "Il lexicon estrae entità e relazioni dai documenti in un knowledge graph, risolve le contraddizioni in base alla policy e ri-ordina i fatti recuperati per similarità semantica. Un motore di guida inietta pattern FOLLOW deterministici o apprende nuove direttive ADAPT.",
 "mem.kg.sparql.label": "SPARQL 1.1<span class=\"mono\">RDF nativo</span>",
 "mem.kg.sparql.p": "Un triple store RDF integrato con parsing TTL risponde a query SPARQL 1.1 SELECT — basic graph pattern, FILTER, OPTIONAL, UNION, MINUS, BIND, VALUES, property path, sub-select e aggregazione con GROUP BY e HAVING — con limiti di sicurezza sui risultati.",
 "mem.kg.rerank.label": "Ri-ordinamento semantico<span class=\"mono\">rilevanza</span>",
 "mem.kg.rerank.p": "Ontologie caricate da catalogo, isolamento per tenant e ri-ordinamento semantico permettono al retrieval di appoggiarsi al significato strutturato e non alla sola sovrapposizione di parole chiave.",
 "mem.kg.cap": "Interroga il knowledge graph con SPARQL 1.1:",
 "mem.okf.tag": "Interscambio di conoscenza portabile",
 "mem.okf.h2": "OKF in ingresso; lexicon e RDF in uscita",
 "mem.okf.p": "Jikji collega l'Open Knowledge Format (markdown più frontmatter YAML) al suo grafo lexicon nativo e alla pipeline RDF/TTL, preservando al contempo un bundle portabile che altri sistemi possono leggere.",
 "mem.okf.1.h": "Round-trip senza perdite",
 "mem.okf.1.p": "Gli strumenti nativi <code>okf.load</code> e <code>okf.export</code> eseguono il round-trip dell'esempio versionato in Markdown con frontmatter YAML, mantenendo identità deterministiche, percorsi confinati e una verifica portabile dell'adattatore di riferimento.",
 "mem.okf.2.h": "Tipizzato e verificabile",
 "mem.okf.2.p": "I link OKF portabili restano markdown leggibile; Jikji aggiunge relazioni tipizzate, confidenza, citazioni di evidenza, provenienza e record di grafo interrogabili, senza vincolare la sorgente a un formato proprietario.",
 "mem.db.tag": "galley — storage",
 "mem.db.h2": "Il database che già usi",
 "mem.db.p": "Tutto lo stato persistente — memoria, run, task, marketplace, credenziali, audit — vive in un unico schema esplicito e migrato dietro lo spazio di lavoro <span class=\"mono\">galley</span>.",
 "mem.db.1.k": "SQLite",
 "mem.db.1.v": "Il default: stato persistente integrato e a configurazione zero per desktop e deploy a nodo singolo, con modalità WAL e gestione dei retry su database occupato.",
 "mem.db.2.k": "PostgreSQL",
 "mem.db.2.v": "Runtime a database condiviso per l'alta affidabilità multi-nodo, con migrazioni consapevoli del dialetto e un gestore di lease distribuito per il recupero dei task.",
 "mem.db.3.k": "MySQL",
 "mem.db.3.v": "Una seconda opzione a database condiviso per l'alta affidabilità multi-nodo, dietro lo stesso schema e lo stesso percorso di migrazione.",
 "mem.db.4.k": "sqlite-vec",
 "mem.db.4.v": "Un backend vettoriale nativo collegato al percorso di recall, usato quando l'estensione sqlite-vec è presente.",
 "mem.db.note": "<b>Le sessioni sono dati di prima classe.</b> La libreria delle sessioni elenca, riprende, rinomina ed elimina le conversazioni — ed esegue il <b>fork</b> di una conversazione da qualsiasi messaggio in un nuovo ramo, con viste complete dell'albero dei fork, così puoi esplorare alternative senza perdere il filo originale.",
 "onto.kicker": "ontobuild · pkg/ontology",
 "onto.title": "Un motore di ontologia <span class=\"accent\">nativo</span>",
 "onto.sub": "La maggior parte degli stack aggancia di lato un database a grafo separato. Jikji costruisce e serve i grafi di conoscenza <b>dentro il binario</b>: un motore in Go puro che ricava un'ontologia dai tuoi documenti e vi risponde in SPARQL 1.1, senza alcun triple store esterno da gestire.",
 "onto.b.tag": "ontobuild — il motore di costruzione",
 "onto.b.h2": "Da un corpus a un'ontologia fondata sui fatti",
 "onto.b.p": "Puntalo su un corpus e ne ricava lo schema e i fatti: non solo triple, ma le classi e le relazioni che le tengono insieme, validate man mano che arrivano.",
 "onto.b.1.label": "Costruzione emergente<span class=\"mono\">schema discovers itself</span>",
 "onto.b.1.p": "La costruzione emergente ricava classi, relazioni e prefissi CURIE di un'ontologia dal materiale di origine stesso, anziché richiedere uno schema in anticipo — con round di analisi facoltativi che approfondiscono la struttura.",
 "onto.b.2.label": "Estrazione &amp; sintesi<span class=\"mono\">documents → triples</span>",
 "onto.b.2.p": "Un codec di estrazione trasforma i documenti in triple tipizzate, e una passata di sintesi compone una struttura di livello superiore al di sopra — così il grafo cattura il significato, non le sole menzioni.",
 "onto.b.3.label": "Ancoraggio &amp; lint<span class=\"mono\">stays clean</span>",
 "onto.b.3.p": "L'ancoraggio convalida ogni nuova relazione rispetto al testo sorgente prima di accettarla, scarta le triple frutto di allucinazioni, e il linting nativo mantiene l'ontologia coerente al suo interno — così la qualità non degrada con la crescita del grafo.",
 "onto.b.4.label": "Incrementale &amp; idempotente<span class=\"mono\">grow, don't rebuild</span>",
 "onto.b.4.p": "Avvia una costruzione da un'ontologia precedente e aggiungi solo ciò che è nuovo: un accumulatore deduplica le triple, così esecuzioni ripetute sono idempotenti. Pensato per aggiornarsi su pianificazione tramite il cron di <code>almanac</code>, non per essere ricostruito da zero.",
 "onto.b.cap": "Costruisci o aggiorna dalla CLI: fonda nuovi fatti, approfondisci con round di analisi, fai crescere un grafo esistente:",
 "onto.s.tag": "pkg/ontology — il motore di query",
 "onto.s.h2": "Servito in-process, interrogato con SPARQL",
 "onto.s.p": "Il grafo vive in uno store RDF in Go puro all'interno del runtime. Gli agenti lo interrogano come strumento, il planner ne è potenziato e gli operatori lo raggiungono via API — il tutto senza un database separato.",
 "onto.s.1.h": "SPARQL 1.1, integrato",
 "onto.s.1.p": "Un motore SPARQL scritto da zero — lexer, parser ed evaluator — risponde a SELECT con pattern di grafo di base, FILTER, OPTIONAL, UNION, MINUS, BIND, VALUES, percorsi di proprietà, sottoquery e aggregazione (GROUP BY / HAVING), con limiti di sicurezza sulla dimensione dei risultati.",
 "onto.s.2.h": "Store RDF in Go puro",
 "onto.s.2.p": "Uno store di triple in memoria e indicizzato, con parsing e serializzazione TTL, gestione dei prefissi e ciclo di vita freeze/unload — niente JVM, niente sidecar, nessun database a grafo esterno da far funzionare.",
 "onto.s.3.h": "Ricerca semantica &amp; riordino",
 "onto.s.3.p": "Lo strumento <code>ontology.search</code> fonde la ricerca nel grafo con un riordino semantico sugli embedding, così il recupero poggia su un significato strutturato. Gli embedding sono opzionali (Jina, OpenAI o Ollama) e, se disattivati, ripiegano sul solo grafo.",
 "onto.s.4.h": "Potenzia il planner",
 "onto.s.4.p": "Oltre ai fatti, il livello <code>lexicon</code> porta situazioni e template di workflow che iniettano contesto nel ciclo dell'agente — così l'ontologia plasma il modo in cui l'agente pianifica, non solo ciò che può consultare. Isolato per tenant dall'inizio alla fine.",
 "onto.s.cap": "Interroga il grafo in tempo reale con SPARQL 1.1 — tramite gli strumenti <span class=\"mono\">lexicon.query</span> / <span class=\"mono\">ontology</span> o l'API:",
 "onto.s.note": "<b>Perché il nativo conta</b> — costruire e servire il grafo nel runtime Jikji mantiene l'ontologia insieme al deployment governato, dal portatile al cluster, senza un servizio grafico separato da gestire o proteggere.",
 "onto.h.tag": "Gestione ibrida dei dati",
 "onto.h.h2": "Un'ontologia sui tuoi dati",
 "onto.h.p": "Un grafo di conoscenza è più utile quando poggia su dati operativi reali. Jikji abbina l'ontologia a uno store relazionale governato, a pipeline e a caching — il modello «ontologia sui dati» delle moderne piattaforme decisionali, realizzato in modo nativo dentro un runtime di agenti.",
 "onto.h.1.h": "Grafo e tabelle, insieme",
 "onto.h.1.p": "L'ontologia è un livello semantico sopra lo store relazionale di <code>galley</code> (SQLite, PostgreSQL o MySQL). Gli agenti ragionano su entrambi — il significato nel grafo e le righe nel database — in un'unica esecuzione.",
 "onto.h.2.h": "Accesso SQL governato",
 "onto.h.2.p": "Uno strumento SQL consente agli agenti di interrogare i dati, ma <code>sqlguard</code> applica una allowlist di istruzioni e tabelle — in sola lettura per impostazione predefinita — e <code>galley</code> inserisce un predicato tenant_id affinché ogni query sia circoscritta al proprio tenant. L'analisi non esce mai dai limiti della policy.",
 "onto.h.3.h": "Pipeline &amp; caching",
 "onto.h.3.p": "Importa ed esporta i dati con strumenti di pipeline e tieni i risultati intermedi in cache con namespace per tenant e in una cache semantica delle risposte — così l'analisi ripetuta è veloce e non ripaga lo stesso lavoro.",
 "onto.h.4.h": "Analisi nel ciclo",
 "onto.h.4.p": "Metti insieme tutto questo e un agente può estrarre righe con SQL governato, incrociarle con l'ontologia, mettere in cache gli intermedi e ragionare sul risultato — un livello dati versatile che trasforma i dati operativi in risposte.",
 "onto.h.5.h": "Data science e ML, dentro il ciclo",
 "onto.h.5.p": "Estrai righe con SQL governato, riutilizzale dalla cache e passale a uno strumento Python che esegue pandas, NumPy o scikit-learn — analisi e modellazione avvengono all'interno di una singola esecuzione dell'agente, non a parte in un notebook separato.",
 "onto.h.6.h": "L'ontologia audita il sistema",
 "onto.h.6.p": "Modella il tuo stesso sistema come un'ontologia: i componenti sono nodi e <b>gli invarianti sono predicati verificabili</b> su osservazioni dal vivo. Il confronto meccanico di un'osservazione con il suo invariante produce una violazione, materializzata nel grafo — così «il sistema è sano» è un'affermazione che va dimostrata con l'evidenza di zero violazioni, mai autodichiarata.",
 "onto.h.f1": "DB SQL",
 "onto.h.f2": "Cache SQL",
 "onto.h.flow": "Interroga una volta, riutilizza il risultato in cache e analizzalo con lo stack scientifico che fornisci nella sandbox — jikji è a suo agio con i dati quanto con la chat.",
 "pn.enterprise": "Enterprise &amp; sicurezza",
 "ent.kicker": "Governata come un'infrastruttura",
 "ent.title": "Governance <span class=\"accent\">integrata</span>, non aggiunta dopo",
 "ent.sub": "Multi-tenancy, autorizzazione, mascheramento, audit, tracing e quote sono moduli del cuore della piattaforma, non plugin aggiunti dopo una violazione. Jikji è progettato per il giorno in cui una piattaforma per agenti dovrà rispondere a sicurezza, compliance e finanza.",
 "ent.perm.tag": "imprimatur · rubric · screen",
 "ent.perm.h2": "Identità, autorizzazione e un piano di policy",
 "ent.perm.p": "Identità, decisioni di autorizzazione, filtraggio dinamico delle policy e pubblicazione dei servizi sono quattro preoccupazioni separate dietro quattro confini.",
 "ent.perm.1.h": "Tenancy &amp; RBAC",
 "ent.perm.1.p": "Principali multi-tenant da chiavi API con ambito definito, con ambiti <code>resource:action</code> e caratteri jolly gerarchici — oltre a policy di risorse/azioni in stile IAM (consenti/nega, fino al singolo strumento) che puoi collegare a una chiave e sovrascrivere in fase di esecuzione senza riavvio. Un simulatore di policy ti consente di convalidare e testare una modifica prima che entri in produzione. L'autenticazione fallisce in modo chiuso: i principali anonimi non ricevono mai l'accesso completo, e le chiavi nuove richiedono ambiti espliciti.",
 "ent.perm.2.h": "Piano decisionale",
 "ent.perm.2.p": "Un piano di autorizzazione dedicato valuta tenant, principal, azione e contesto dello strumento per emettere un <code>allow</code>, un <code>deny</code> o un <code>ask</code> — e registra ogni decisione, con una motivazione sia in caso di consenso sia di rifiuto, in una traccia di audit strutturata.",
 "ent.perm.3.h": "Catena di filtri dinamica",
 "ent.perm.3.p": "Filtri di richiesta componibili con predicati condizionali <code>when</code> (orario, ambiente, attributi della richiesta), gate di approvazione, chiamate a policy esterne con un interruttore di sicurezza e modalità di permesso <code>auto</code> / <code>ask</code> / <code>deny</code> — crea uno snapshot della catena attiva e riportala a una versione nota come valida a runtime.",
 "ent.perm.4.h": "Approva ciò che gli agenti espongono",
 "ent.perm.4.p": "Gli agenti possono definire le proprie superfici UI e API; gli operatori le elencano, le approvano o le revocano una per una dal piano di servizio — tramite API, <code>jikjictl service</code> o la dashboard — governati dallo stesso percorso di policy di ogni altra azione.",
 "ent.perm.cap": "Le policy sono dati: le regole si risolvono in allow, ask o deny e bloccano per impostazione predefinita:",
 "ent.mt.tag": "Multitenancy &amp; personalizzazione",
 "ent.mt.h2": "Un servizio, molti tenant, a ciascun utente il proprio",
 "ent.mt.p": "Un modello di utenza pensato per le aziende è integrato di serie. Attiva un servizio per ogni tenant, lascia che gli utenti vi accedano tramite chiavi client con ambito definito e offri a ciascuno un agente privato e personalizzato — senza dover eseguire un deployment separato per nessuno.",
 "ent.mt.1.h": "Un tenant è un confine di servizio",
 "ent.mt.1.p": "Ogni tenant ha le proprie chiavi, dati, memoria e policy. Attiva un servizio per tenant — o per team, cliente o ambiente — tutti sullo stesso cluster, completamente isolati l'uno dall'altro.",
 "ent.mt.2.h": "Ogni utente è un principal con ambito definito",
 "ent.mt.2.p": "Gli utenti accedono a un servizio come principal dotati di scope, e una sola chiave di servizio può contenerne molti. Un'identità actor su ogni richiesta distingue un utente finale dall'altro, così restano separati senza bisogno di una chiave per persona; gli scope continuano a decidere, a ogni richiesta, cosa ciascuno può fare.",
 "ent.mt.3.h": "Memoria isolata per utente",
 "ent.mt.3.p": "Il richiamo e l'acquisizione sono partizionati per tenant <em>e</em> attore, e impressi su ogni esecuzione a partire dal principal — così un utente non vede mai la memoria di un altro, nemmeno all'interno dello stesso servizio.",
 "ent.mt.4.h": "Risposte iper-personalizzate",
 "ent.mt.4.p": "I fatti propri di ciascun utente e la sua ontologia personale plasmano il modo in cui l'agente gli risponde — un contesto personalizzato iniettato per principal, e non un unico prompt condiviso da tutti.",
 "ent.mt.eg": "<b>Un servizio, una chiave, molti clienti.</b> Il cliente A e il cliente B accedono entrambi al servizio <span class=\"mono\">asdf</span> tramite la stessa chiave, ma ogni richiesta porta con sé la propria identità actor: così la loro memoria, il contesto e la personalizzazione restano separati, e ciascuno vive un'esperienza privata creata solo per lui.",
 "ent.sec.tag": "Credenziali &amp; protezione dei dati",
 "ent.sec.h2": "Segreti, mascheramento e difesa dalle injection",
 "ent.sec.1.h": "Vault &amp; OAuth",
 "ent.sec.1.p": "Uno store di credenziali AES-GCM (su file o basato su galley) con rotazione e audit degli accessi, gestibile da CLI, API o dashboard. I provider possono usare credenziali da env, vault o OAuth, con login da dispositivo e refresh dei token, e le chiavi inline vengono mascherate nell'export della configurazione.",
 "ent.sec.2.h": "Mascheramento di PII &amp; segreti",
 "ent.sec.2.p": "Il modulo <code>proof</code> rileva e maschera in modo reversibile PII e segreti con segnaposto stabili prima che il testo venga pubblicato o inviato verso l'esterno, ripristinando i valori per il chiamante e gestendo in sicurezza i confini dei chunk nelle risposte in streaming.",
 "ent.sec.3.h": "Difesa dalle prompt injection",
 "ent.sec.3.p": "I contenuti non fidati vengono evidenziati e disinnescati, e il taint tracking blocca gli strumenti sensibili una volta che un'esecuzione ha ingerito dati esterni, difendendo dai tentativi di override delle istruzioni e di jailbreak.",
 "ent.sec.4.h": "Controllo SSRF &amp; del traffico in uscita",
 "ent.sec.4.p": "Il traffico HTTP in uscita dai controlli di policy e dalle estensioni iniettate passa per i controlli SSRF dialguard contro allowlist esplicite, bloccando loopback e range privati a meno che non siano deliberatamente consentiti.",
 "ent.pii.tag": "proof — PII e segreti",
 "ent.pii.h2": "La fuga fermata all'origine",
 "ent.pii.p": "Sui percorsi runtime collegati a <code>Proof</code>, i valori che corrispondono ai modelli <code>regex</code> integrati, locali o personalizzati abilitati possono essere mascherati prima dell'elaborazione coperta di provider, strumenti o log. I percorsi di ritorno coperti possono ripristinare i valori mappati; la modalità drop omette intenzionalmente il ripristino. Formati non riconosciuti e percorsi esterni a Proof restano fuori da questo controllo, quindi l'operatore deve configurare i modelli e verificare ogni percorso dati.",
 "ent.pii.d1": "i tuoi dati",
 "ent.pii.d2": "mascheramento",
 "ent.pii.d3": "modello · strumento · log",
 "ent.pii.d4": "ripristino",
 "ent.pii.flow": "Su un percorso <code>Proof</code> configurato, un valore che corrisponde a un <code>regex</code> abilitato può diventare un segnaposto stabile come <span class=\"mono\">[PII_EMAIL_1]</span>. Valori non riconosciuti e percorsi fuori da Proof passano invariati.",
 "ent.pii.1.h": "Mascherato prima di uscire",
 "ent.pii.1.p": "Sui percorsi esplicitamente integrati con <code>Proof</code>, i modelli <code>regex</code> abilitati oscurano input o output di strumenti corrispondenti prima del confine coperto di uscita o persistenza. È difesa in profondità: testare ogni percorso configurato e ridurre i dati sensibili, perché le regex non rilevano ogni formato.",
 "ent.pii.2.h": "Integro per l'utente reale",
 "ent.pii.2.p": "Segnaposto reversibili e stabili vengono ripristinati per chi effettua la chiamata, così la vista dell'utente finale resta integra — il giro completo del mascheramento è per lui invisibile, senza nulla di alterato o perso.",
 "ent.pii.3.h": "Sicuro in streaming ed effimero",
 "ent.pii.3.p": "I segnaposto vengono ripristinati correttamente anche a cavallo dei confini dei chunk in streaming, e la mappa dei segnaposto è legata al tenant e non viene mai persistita — vive soltanto per la durata della richiesta.",
 "ent.obs.tag": "Osservabilità &amp; costi",
 "ent.obs.h2": "Vedilo, traccialo, mettigli un tetto",
 "ent.obs.1.h": "Tracing con OpenTelemetry",
 "ent.obs.1.p": "Tracce OTLP via gRPC o HTTP con propagazione del trace-context W3C e head sampling, ID di correlazione lungo tutto il percorso della richiesta e log di accesso strutturati.",
 "ent.obs.2.h": "Metriche &amp; profiling",
 "ent.obs.2.p": "Un endpoint Prometheus <code>/metrics</code> con cardinalità delle label limitata, metriche su run e passi degli agenti, contatori di dispatch ed endpoint pprof per il profiling live.",
 "ent.obs.3.h": "Limiti d'uso &amp; quote",
 "ent.obs.3.p": "Monitora le quote dei provider esterni (finestre mobili e settimanali) e applica quote interne per tenant, con endpoint di amministrazione, indicatori, pannelli della dashboard e <code>jikjictl provider usage</code>. Quando si raggiunge la finestra di un provider (un limite di 5 ore o un 429), il dispatch riprova in modo durevole dopo che si è liberata, invece di far fallire il lavoro.",
 "ent.obs.5.h": "Guardia dei costi",
 "ent.obs.5.p": "Imposta fasce di costo per modello e budget che sostengono una guardia dei costi — limita anche i pannelli multi-modello di <code>trinity</code> così che un ensemble non possa spendere troppo. Gestisci fasce e budget con <code>jikjictl cost</code>.",
 "ent.obs.4.h": "Debug live, agganciabile al volo",
 "ent.obs.4.p": "Il collegamento live usa sessioni PTY Unix tramite un terminale basato su WebSocket ed è qualificato in modo nativo su Linux; Windows ConPTY non è supportato. Indipendentemente dalle capacità del terminale, la traccia dei passi JSONL riproduce un'esecuzione dall'inizio alla fine e <code>/debug/pprof</code> profila il processo attivo.",
 "ent.rob.tag": "Robustezza &amp; operatività",
 "ent.rob.h2": "Costruito per superare la giornata storta",
 "ent.rob.1.h": "Recupero &amp; persistenza",
 "ent.rob.1.p": "Checkpoint convalidati per ogni passo con protezioni dal replay correlate, retry su SQLITE_BUSY e gestori di lease distribuiti che segnalano chiaramente gli errori invece di fingere il successo.",
 "ent.rob.2.h": "Isolamento dei guasti",
 "ent.rob.2.p": "Circuit breaker per provider, code limitate con lease di tipo claim-and-settle, retry con backoff e svuotamento controllato allo spegnimento.",
 "ent.rob.3.h": "Integrità della supply chain",
 "ent.rob.3.p": "Installazioni dal marketplace firmate (Ed25519 o HMAC) con checksum verificati, e un firewall in uscita che blocca per impostazione predefinita se il suo filtro non si installa.",
 "ent.rob.4.h": "Canali &amp; webhook",
 "ent.rob.4.p": "Un'interfaccia di adattatori di canale modulare guida le esecuzioni dell'agente dalle piattaforme di messaggistica — oggi un adattatore Telegram, progettato per andare oltre (Slack e non solo) — oltre a webhook in entrata firmati, con ambiti degli strumenti per ogni chat, allowlist e limiti di frequenza.",
 "ent.rob.5.h": "Configurazione &amp; ricarica",
 "ent.rob.5.p": "Export della configurazione per gli operatori e ricarica a caldo via API, CLI e dashboard, con un parsing della configurazione deterministico, validato e coperto da test.",
 "ent.rob.6.h": "Strumenti per gli operatori",
 "ent.rob.6.p": "<code>jikjictl</code> per credenziali, RBAC, policy, filtri, audit, tracing, consumi e marketplace — più una dashboard web che non memorizza mai le chiavi lato server: un playground con snapshot, rollback e approvazione delle inquiry sul posto; viste dei filtri con badge del circuit breaker; policy IAM con il simulatore; superfici del piano di servizio; pannelli dei consumi; e gestione del vault.",
 "ent.cli.cap": "Gestisci tutto dalla CLI per gli operatori:",
 "ent.upd.tag": "Operatività senza interruzioni",
 "ent.upd.h2": "Aggiornalo senza spegnerlo",
 "ent.upd.p": "Una piattaforma che fa girare il business non può fermarsi per essere riconfigurata. Jikji è fatto per cambiare a caldo: svuotarsi in modo pulito, ricaricare la configurazione sul posto e distribuire gli aggiornamenti su un cluster che non smette mai di servire.",
 "ent.upd.1.h": "Svuotamento graduale",
 "ent.upd.1.p": "Allo spegnimento il nodo smette di accettare nuovo lavoro, lascia terminare le esecuzioni in corso e solo allora esce — così un riavvio o un nuovo deploy non interrompe mai una sessione a metà.",
 "ent.upd.2.h": "Ricarica della configurazione a caldo",
 "ent.upd.2.p": "Esporta e ricarica la configurazione del runtime via API, CLI o dashboard senza riavviare — cambia provider, filtri e policy a caldo, con un parsing deterministico e validato.",
 "ent.upd.3.h": "Aggiornamenti progressivi tramite HA",
 "ent.upd.3.p": "Con la HA attiva, i controller condividono un unico database ed eleggono un solo leader per gli scheduler singleton mentre ogni nodo serve traffico — così aggiorni i nodi uno alla volta e il cluster continua a girare.",
 "tools.kicker": "sorts — il runtime degli strumenti",
 "tools.title": "I <span class=\"accent\">sorts</span> che il loop compone",
 "tools.sub": "Gli strumenti sono i caratteri mobili che Jikji compone uno a uno — un ampio catalogo integrato più tutto ciò che installi, ciascuno eseguito dietro un gate di policy e una sandbox, in locale o su un nodo remoto.",
 "tools.cat.tag": "Il catalogo",
 "tools.cat.h2": "Strumenti integrati, pronti all'uso",
 "tools.cat.p": "Un agente che lavora ha bisogno di ben più di una casella di chat. Jikji include un'ampia dotazione di strumenti perché un agente possa leggere, cercare, navigare, interrogare, analizzare e agire fin dalla prima esecuzione.",
 "tools.cat.1.k": "Workspace",
 "tools.cat.2.k": "Web &amp; browser",
 "tools.cat.3.k": "Dati",
 "tools.cat.3.v": "(gestito da sqlguard)",
 "tools.cat.4.k": "Conoscenza",
 "tools.cat.4.v": "(SPARQL)",
 "tools.cat.5.k": "Orchestrazione",
 "tools.cat.8.k": "Obiettivi &amp; pianificazione",
 "tools.cat.9.k": "Pubblica",
 "tools.cat.6.k": "Ricerca &amp; competenze",
 "tools.cat.7.k": "Canali",
 "tools.cat.7.v": "(Telegram)",
 "tools.cat.7.v2": "webhook in entrata",
 "tools.cat.note": "Ogni chiamata a uno strumento passa prima dal piano di policy <span class=\"mono\">rubric</span>, così un agente esegue solo ciò che il suo tenant e i suoi scope consentono.",
 "tools.fn.tag": "Estendilo tu stesso",
 "tools.fn.h2": "Una funzione è uno strumento",
 "tools.fn.p": "Non serve ricompilare per aggiungere una funzionalità. Scrivi una funzione Lua o Python — o un intero script Python —, pubblicala e viene registrata come strumento di prima classe a runtime, dietro lo stesso gate di policy e la stessa sandbox e esponibile via MCP, proprio come quelli integrati. Python gira a livello di funzione per un aiutante rapido o a livello di script per lavori più impegnativi.",
 "tools.fn.cap": "Pubblicala sul <span class=\"mono\">bookstore</span> e si registra in automatico — senza ricompilare, con verifica della firma opzionale prima dell'esecuzione.",
 "loop.t.tag": "Gli strumenti — sorts",
 "loop.t.h2": "Un runtime di strumenti in sandbox",
 "loop.t.p": "Gli strumenti sono i <span class=\"mono\">sorts</span> mobili che il ciclo compone al loro posto: integrati o installati, eseguiti in locale o su un nodo remoto, sempre dietro un gate di policy e una sandbox.",
 "loop.t.1.h": "Strumenti integrati &amp; runner",
 "loop.t.1.p": "Lettura/ricerca/elenco/sostituzione/scrittura di file, shell, ricerca web, un browser headless (schede, estrazione del DOM, salvataggio del sorgente), un lettore web a contenuto pulito con recupero delle pagine, strumenti di ontologia e di canale, e skill. I runner comprendono sottoprocessi Python in sandbox, un motore Lua integrato, comandi locali e nodi remoti.",
 "loop.t.2.h": "MCP, in entrambe le direzioni",
 "loop.t.2.p": "Un client Model Context Protocol comunica con i server stdio e registra i loro strumenti nella toolbox. Un server espone gli strumenti di Jikji a qualsiasi host MCP. Le chiamate agli strumenti vengono collegate in entrambe le direzioni, con streaming.",
 "loop.t.3.h": "Sandbox a difesa in profondità",
 "loop.t.3.p": "Namespace Linux, Landlock, seccomp e RLIMIT imposti dal processo padre, più i limiti di cgroup v2. Modalità di rete <code>none</code>, <code>loopback</code> o <code>host</code> con una allowlist in uscita, applicata al confine delle syscall e che blocca per impostazione predefinita se il filtro non si installa.",
 "loop.t.4.h": "Nodi strumento remoti",
 "loop.t.4.p": "Sposta l'esecuzione degli strumenti sui worker <code>jikji-tool-node</code> attraverso un tunnel TLS <code>jikji-relay</code>, con un catalogo condiviso persistente, circuit breaker e failover per nodo, senza toccare l'agente.",
 "loop.t.5.h": "Marketplace &amp; firma",
 "loop.t.5.p": "Pubblica strumenti Lua o Python nel <code>bookstore</code>, installali e registrali automaticamente a runtime. Le installazioni possono richiedere firme Ed25519 o HMAC, con checksum verificati prima ancora che uno strumento venga eseguito.",
 "loop.t.6.h": "Difesa dalle prompt injection",
 "loop.t.6.p": "I contenuti esterni non fidati vengono evidenziati con marcatori avvolti da nonce e disinnescati; il taint tracking blocca gli strumenti sensibili (shell, scrittura, rete) quando un'esecuzione ha ingerito dati non fidati. Tra i segnali rilevati ci sono i tentativi di override delle istruzioni e di jailbreak.",
 "tools.xr.note": "Gli strumenti non devono essere eseguiti dove l'agente sta pensando — vedi <a href=\"orchestration.html\">orchestrazione di strumenti cross-region</a> sulla pagina Orchestration",
 "about.crumb": "Informazioni",
 "about.kicker": "Jikji Labs",
 "about.title": "Informazioni su <span class=\"accent\">Jikji Labs</span>",
 "about.sub": "Jikji Labs sviluppa Jikji, una piattaforma di agenti modulare ispirata ai caratteri mobili in metallo. Crediamo che l'infrastruttura per gli agenti debba essere componibile, governata e duratura fin dal primo giorno, proprio come i caratteri mobili hanno reso la stampa affidabile su larga scala.",
 "about.p1": "<b>Jikji</b> è un runtime Go modulare per loop di agenti deterministici, orchestrazione multimodello adattiva, un piano di memoria che apprende, un motore di ontologia nativo e governance enterprise — distribuibile da un portatile a un cluster multi-nodo.",
 "about.c.tag": "Mettiti in contatto",
 "about.c.h2": "Contatta il team",
 "about.maint.k": "Manutentore",
 "about.email.k": "E-mail",
 "about.li.k": "LinkedIn",
 "about.gh.k": "GitHub",
 "about.note": "Jikji Labs è un progetto indipendente. Questa pagina descrive ciò che è presente oggi nel codice; le API e i confini tra i moduli potrebbero cambiare prima della prima versione stabile.",
 "nav.usecases": "Casi d'uso",
 "uc.kicker": "esempi — un manuale di schemi eseguibili",
 "uc.title": "Cosa puoi <span class=\"accent\">costruire</span> con Jikji",
 "uc.sub": "Ogni pattern corrisponde a configurazione, comandi o evidenza nel repository. I meccanismi deterministici sono separati dalle esecuzioni live dipendenti dal provider, così puoi vedere esattamente cosa è stato esercitato e cosa dipende ancora dal tuo ambiente.",
 "uc.g1.tag": "Costruire un agente",
 "uc.g1.h2": "Da una chiamata di chat a un'esecuzione guidata da obiettivi",
 "uc.g1.p": "Parti da dove sei — un endpoint compatibile con OpenAI pronto all'uso — e poi cresci verso esecuzioni guidate da obiettivi e ragionamento multi-modello, senza cambiare stack.",
 "uc.chat.h": "Chat compatibile con OpenAI",
 "uc.chat.p": "Punta un client OpenAI esistente su Jikji: <code>POST /v1/chat/completions</code>, senza streaming o in flusso SSE. Cambia l'URL di base e mantieni il tuo codice.",
 "uc.run.h": "Esecuzioni di agenti guidate da obiettivi",
 "uc.run.p": "Trasforma un obiettivo in un'esecuzione con checkpoint e riproducibile con <code>jikjictl run</code> e <code>POST /v1/runs</code>, trasmessa passo dopo passo — il ciclo deterministico <code>forme</code>, non una catena opaca.",
 "uc.multi.h": "Ragionamento multi-modello",
 "uc.multi.p": "Avvia un dibattito a sciame, un confronto con giudice o un ciclo di agente su più modelli contemporaneamente — scegli la risposta più forte, o falla verificare da un collegio.",
 "uc.tools.h": "Scoprire &amp; richiamare strumenti",
 "uc.tools.p": "Elenca il catalogo di strumenti dell'agente e invoca uno qualsiasi direttamente con <code>POST /v1/tools/call</code> — gli stessi strumenti che usa il ciclo, disponibili tramite l'API.",
 "uc.lua.h": "Strumenti Lua &amp; Python personalizzati",
 "uc.lua.p": "Registra il tuo strumento come script Lua o funzione Python <code>run(input)</code> ed entra nel catalogo — senza ricompilare, vincolato come qualsiasi strumento integrato.",
 "uc.g2.tag": "Strumenti, dati &amp; analisi",
 "uc.g2.h2": "Leggere, interrogare e calcolare — con esecuzione governata",
 "uc.g2.p": "Dai a un agente capacità reali senza rinunciare a confini espliciti: gli strumenti per file, query e comandi passano attraverso controlli di policy, mentre la robustezza della sandbox a livello di sistema operativo dipende dal runner e dalla piattaforma host selezionati.",
 "uc.file.h": "Strumenti per i file dell'area di lavoro",
 "uc.file.p": "Circoscrivi un agente a un insieme di radici e lascia che legga, cerchi, scriva ed elenchi file — protetto per percorso, così non evade mai l'area di lavoro che gli concedi.",
 "uc.sql.h": "Accesso SQL governato",
 "uc.sql.p": "Esponi uno strumento SQL in sola lettura (SELECT) con una policy di accesso a strati, per tenant — l'agente interroga i dati a cui è autorizzato, e nient'altro.",
 "uc.data.h": "Pipeline di dati in stile Palantir",
 "uc.data.p": "Combina un'ontologia, una query SQL in sola lettura (SELECT), una cache intermedia e un'analisi <code>extension.python</code> (numpy/pandas) in un'unica pipeline vincolata a KPI — dati, cache e analisi in un solo ciclo.",
 "uc.code.h": "Programmazione &amp; debug consapevoli dei tipi",
 "uc.code.p": "Modifiche ad ancoraggio verificate con hash, un controllo <code>code.check</code> di livello compilatore, rinomina di simboli e test da shell — un agente di programmazione vincolato a un KPI di accettazione misurabile, non a sensazioni.",
 "uc.g3.tag": "Obiettivi &amp; orchestrazione",
 "uc.g3.h2": "Lavoro a lungo orizzonte che sopravvive a un crash",
 "uc.g3.p": "Struttura il lavoro ambizioso come obiettivi misurabili e code durevoli, poi impila le primitive su un unico telaio recuperabile.",
 "uc.goal.h": "Gerarchia di obiettivi con KPI reali",
 "uc.goal.p": "Costruisci un albero di obiettivi annidati con KPI misurabili (lo schema della «graffetta»): accettazione meccanica, prove e un controllo di obsolescenza observedGeneration, così che un obiettivo irrigidito non possa essere falsamente soddisfatto.",
 "uc.compose.h": "Meccanismi componibili",
 "uc.compose.p": "Impila le primitive: obiettivi + una coda di dispatch + <code>trinity.ensemble</code> (multi-modello vincolato a verificatore) + <code>trinity.oracle</code> (controllo di deriva), tutto su un unico telaio durevole.",
 "uc.queue.h": "Lavoro autonomo guidato da coda",
 "uc.queue.p": "Accoda elementi di lavoro e avvia un ciclo di worker che svuota la coda ed esce — oppure attende all'infinito con <code>--keep-waiting</code>. Durevole, sicuro nella presa in carico, riavviabile.",
 "uc.almanac.h": "Job autonomi pianificati",
 "uc.almanac.p": "Job cron e a intervallo che emettono comandi dell'orchestratore, strumenti, lavoro accodato o notifiche — al più una volta e a prova di crash tra un riavvio e l'altro.",
 "uc.runners.h": "Molte superfici di esecuzione, un solo controllo",
 "uc.runners.p": "Instrada gli strumenti su superfici denominate — shell locale, python, browser, nodi-strumento remoti con sandbox docker o ssh — tutto sotto un'unica catena di controllo, dal portatile al cluster.",
 "uc.g4.tag": "Ricerca &amp; conoscenza",
 "uc.g4.h2": "Fondato, citato, verificato in modo avversariale",
 "uc.g4.p": "Fai in modo che un agente citi le pagine catturate e derivi le violazioni dalle prove — risposte che puoi controllare, non congetture sicure di sé.",
 "uc.web.h": "Ricerca web fondata",
 "uc.web.p": "Cerca, apri, leggi e salva le fonti, poi lega ogni affermazione a una pagina catturata con <code>research.source</code> — citata da pagine reali, non dai dati di addestramento.",
 "uc.onto.h": "Revisione meccanica degli invarianti",
 "uc.onto.p": "Asserisci predicati, fornisci osservazioni misurate e <b>deriva</b> le violazioni in modalità fail-closed — materializzando un grafo di contraddizioni invece di chiedere a un modello di «controllare».",
 "uc.paper.h": "Scrittura verificata in modo avversariale",
 "uc.paper.p": "Scrivi un articolo tecnico in cui ogni affermazione è un KPI: un controllo di ambiguità, affermazioni di obiettivo, fonti web, <code>system.review</code> e un passaggio di ensemble/oracle <code>trinity</code> prima che regga.",
 "uc.kg.h": "Ontologia &amp; grafo della conoscenza nativi",
 "uc.kg.p": "Costruisci e servi ontologie in modo nativo — TTL, SPARQL tramite <code>lexicon.query</code> e <code>ontology.search</code> semantico — uno strato di conoscenza su cui il ciclo ragiona direttamente.",
 "uc.g5.tag": "Integrare &amp; interoperare",
 "uc.g5.h2": "Interoperabilità tramite MCP, ACP e A2A",
 "uc.g5.p": "Esponi Jikji come un server che altri sistemi già sanno come chiamare — MCP, ACP, A2A — e collega i canali in cui vivono i tuoi utenti.",
 "uc.mcp.h": "Server MCP",
 "uc.mcp.p": "Esponi gli strumenti di Jikji come un server Model Context Protocol su stdio o HTTP — qualsiasi client MCP li pilota direttamente.",
 "uc.acp.h": "ACP tramite stdio e HTTP",
 "uc.acp.p": "Usa JSON-RPC tramite stdio per i client ACP locali, oltre a un manifest HTTP e a un’interfaccia di invocazione per le integrazioni remote.",
 "uc.a2a.h": "Registro agente-a-agente",
 "uc.a2a.p": "Scopri e osserva agenti nel registro A2A su gRPC — il substrato per agenti che si trovano e si chiamano a vicenda.",
 "uc.tg.h": "Bot Telegram → esecuzioni di agenti",
 "uc.tg.p": "Esegui un bot Telegram che trasforma ogni messaggio in un'esecuzione di agente — risposte in streaming, comandi slash, proprio dove i tuoi utenti sono già.",
 "uc.codex.h": "Codex Responses tramite OAuth per dispositivo",
 "uc.codex.p": "Usa un modello Codex Responses configurato tramite l'OAuth per dispositivo di ChatGPT. Le richieste consumano la quota dell'abbonamento dell'utente e restano soggette ai termini del provider, alla disponibilità del modello e alle finestre di utilizzo mobili.",
 "uc.g6.tag": "Governare &amp; multi-tenant",
 "uc.g6.h2": "Eseguilo come un servizio, per molti utenti",
 "uc.g6.p": "Servi tenant isolati da un unico deployment: ambiti per chiave, confini degli strumenti in negazione predefinita e un marketplace per distribuire ciò che costruisci.",
 "uc.rbac.h": "Chiavi &amp; ambiti per tenant",
 "uc.rbac.p": "Emetti chiavi API, ambiti e associazioni di ruolo per tenant con <code>jikjictl rbac</code> — un deployment, molti utenti isolati, ciascuno con la propria portata.",
 "uc.perm.h": "RBAC ai confini degli strumenti",
 "uc.perm.p": "Richiedi ambiti per strumento, nega in modo predefinito e distribuisci l'autorizzazione in sicurezza con un percorso a fasi <code>observe → warn → enforce</code> più preflight — irrigidisci senza interrompere il traffico.",
 "uc.market.h": "Pubblicare &amp; installare pacchetti",
 "uc.market.p": "Impacchetta uno strumento o un agente registrato, pubblicalo sul marketplace e installalo su un altro tenant — firmato, versionato, un solo comando per adottarlo.",
 "uc.close.p": "<b>Ogni esempio è un pezzo mobile.</b> La vera leva è impilarli — una gerarchia di obiettivi che pilota una coda di dispatch, lavorata da un consiglio vincolato a un verificatore, che cita fonti web e viene controllata da una revisione meccanica. Preleva quelli che ti servono, regolali con precisione, e stampa.",
 "uc.ratelimit.h": "Supera un limite d'uso senza fermarti",
 "uc.ratelimit.p": "Hai raggiunto il limite d'uso di un provider o di un abbonamento ChatGPT (429/529)? Jikji legge la vera finestra di reset — comprese le finestre 5-hour e settimanale di codex — e riprende invece di fallire. Un'esecuzione interattiva attende con <code>--wait-on-rate-limit</code> (limitata da <code>--max-wait</code>, 6h di default); gli agenti dispatchati e le esecuzioni di piano riprendono in autonomia dall'ultimo checkpoint quando la finestra si azzera (<code>rate_limit_resume: park</code>) — nessun client deve restare connesso.",
 "uc.backbone.h": "La spina dorsale intelligente della tua applicazione",
 "uc.backbone.p": "Fai di Jikji il motore di ragionamento dedicato di un'applicazione separata: la tua applicazione mantiene il controllo dei propri dati e dei propri strumenti in sola lettura, invia uno scenario deterministico tramite POST a <code>/v1/runs</code>, e Jikji richiama quegli strumenti attraverso un sottoprocesso MCP dichiarato sotto <code>sorts.mcp_servers</code> — ogni chiamata controllata e verificata. La tua applicazione non importa mai Jikji né incorpora alcun framework di agenti; resta un semplice client HTTP.",
 "uc.council.h": "Un consiglio tra fornitori diversi che la tua CLI di sviluppo non può convocare da sola",
 "uc.council.p": "Una CLI di sviluppo (Claude Code, Codex) ha i propri sub-agenti, ma provengono tutti da un unico fornitore. Per una decisione ad alto rischio — un audit di sicurezza, una scelta di architettura — collega un Jikji in esecuzione tramite <code>/v1/mcp</code> e affida la domanda a un consiglio tra fornitori diversi, regolato da policy, auditato e votato da verificatori (<code>trinity.ensemble</code>): modelli di fornitori distinti rispondono, un panel vota ACCEPT/REVISE e un sintetizzatore fonde le risposte superstiti. A ciò si aggiungono <code>trinity.oracle</code> (controllo del drift) e <code>agent.spawn</code>. Il salto verso MCP vale la pena solo per le decisioni di peso, mai per lo sviluppo di routine.",
 "hero.kicker.current": "Runtime agente enterprise · Rilascio Go senza CGO · GPL predefinito",
 "hero.offer.current": "La piattaforma agente enterprise, composta in caratteri metallici.",
 "proof.tag": "Prova, non una diapositiva di prodotto",
 "proof.h": "Gli esempi sono contratti eseguibili di come si comporta Jikji.",
 "proof.p": "Il repository include scenari eseguibili, configurazione di produzione, artefatti funzionanti e controlli protetti su provider live. Documentano il percorso da un'esecuzione echo locale a un consiglio di cinque fornitori, un worker durevole o un deployment multi-tenant rinforzato. Le affermazioni che dipendono da un provider o ambiente sono etichettate come tali.",
 "proof.cta": "Apri il registro degli esempi",
 "proof.live": "Evidenza live",
 "proof.worked": "Artefatto funzionante",
 "proof.deterministic": "Deterministico",
 "proof.operator": "Percorso operatore",
 "proof.cli": "Un percorso di qualificazione documentato collega una CLI di programmazione a un consiglio cross-vendor tramite HTTP MCP, quindi registra le fasi dei candidati e dei verificatori per l'ispezione.",
 "proof.trinity": "Risposte indipendenti, sintesi e un pannello avversario ACCETTA/RIVEDI con il risultato conservato per ispezione.",
 "proof.queue": "Comportamento di richiesta durevole, lease, completamento e riavvio dimostrato senza fare affidamento sull'opinione di un modello.",
 "proof.ops": "Auth, TLS, policy, audit, redazione, backup, prontezza e osservabilità assemblati come checklist di deployment a chiusura per fallimento.",
 "img.usecases.alt": "Libro di pattern aperto circondato da artefatti del verificatore, una coda durevole, grafico delle attività, topologia di deployment e output dei comandi",
 "img.jikjicode.alt": "Laboratorio di codifica inciso che collega la struttura del codice sorgente, le modifiche di precisione, la verifica, gli strumenti protetti e una stampa finale",
 "ledger.tag": "Evidenza selezionata",
 "ledger.h2": "Inizia da un percorso funzionante, non da un framework vuoto",
 "ledger.p": "Questo catalogo distingue percorsi di integrazione supportati, meccanismi provati, riferimenti operativi ed evidenze di ricerca. Ogni link apre il meccanismo pubblico o l'evidenza operativa pertinente su questo sito.",
 "ledger.th.example": "Esempio",
 "ledger.th.scope": "Cosa copre l'evidenza",
 "ledger.th.tier": "Evidenza · livello di supporto",
 "ledger.cli.scope": "HTTP MCP da una CLI di codifica in un <code>trinity.ensemble</code> a cinque fornitori, Oracle ed esecuzioni figlie durevoli.",
 "ledger.cli.tier": "Qualificazione live documentata · percorso di integrazione",
 "ledger.trinity.scope": "Fan-out dei candidati, sintesi, voto del verificatore e risposta accettata conservata per ispezione.",
 "ledger.trinity.tier": "Esempio eseguibile · meccanismo",
 "ledger.taskgraph.scope": "Sotto-agenti durevoli consapevoli delle dipendenze, ondate concorrenti e serializzazione dei conflitti di file.",
 "ledger.taskgraph.tier": "Eseguibile + artefatto funzionante · meccanismo",
 "ledger.queue.scope": "Richiesta di coda durevole, lease, completamento e comportamento di riavvio del worker.",
 "ledger.queue.tier": "Artefatto funzionante · meccanismo",
 "ledger.prod.scope": "Controlli di auth, TLS, policy, audit, redazione, recupero e telemetria a chiusura per fallimento per qualificarsi nel tuo ambiente.",
 "ledger.prod.tier": "Checklist + configurazione · riferimento operatore",
 "ledger.ha.scope": "PostgreSQL condiviso, elezione del leader, prontezza, drenaggio e topologia multi-nodo.",
 "ledger.ha.tier": "Configurazione + procedura · riferimento di deployment",
 "ledger.relay.scope": "Join firmato Ed25519, credenziali bootstrap con ambito monouso, lease rinnovabili e riconnessione con chiave stabile per nodi strumento remoti.",
 "ledger.coding.tier": "Eseguibile + artefatto funzionante · meccanismo",
 "ledger.approval.tier": "Meccanismo deterministico · modello operativo",
 "ledger.backup.scope": "SQLite <code>VACUUM INTO</code>, verifica dell'integrità, prove basate sull'hash del contenuto e una prova di ripristino che dimostra il contenuto recuperato del database.",
 "ledger.backup.tier": "Procedura eseguibile · riferimento operativo",
 "ledger.audit.scope": "Una catena di hash con chiave rileva record di audit modificati, eliminati o riordinati e segnala il primo collegamento interrotto.",
 "ledger.audit.tier": "Verifica eseguibile · meccanismo di sicurezza",
 "ledger.relay.tier": "Configurazione di esempio + qualificazione del codice sorgente completo · modello operativo",
 "img.arch.alt": "Officina di stampa modulare incisa che mostra stazioni connesse di ingresso, policy, modello, strumento e stato durevole",
 "plate.arch.title": "PERCORSO RICHIESTA",
 "plate.arch.meta": "IN-PROCESS PRIMO · HTTP / gRPC PRONTO",
 "plate.arch.s1h": "press + imprimatur",
 "plate.arch.s1p": "Ingress autentica il tenant e costruisce un principal con ambito",
 "plate.arch.s2h": "rubric + compositor",
 "plate.arch.s2p": "Policy decide; la sessione e il run durevole vengono assemblati",
 "plate.arch.s3h": "typebackbone + sorts",
 "plate.arch.s3p": "Models e tools governati eseguono dietro interfacce stabili",
 "plate.arch.s4h": "galley + proof",
 "plate.arch.s4p": "State, links, audit-safe payloads e evidence persistono",
 "plate.arch.cap": "Ogni boundary è utilizzabile come API Go in-process prima e progettato per spostarsi dietro un protocollo di servizio standard senza riscrivere la regola di business",
 "img.loop.alt": "Imbracatura circolare incisa per agenti che muove lo stato durevole attraverso stazioni di piano, azione, osservazione e checkpoint",
 "loop.research.tag": "Ricerca Harness",
 "loop.research.h2": "Diversi loop delimitati, misurati separatamente",
 "loop.research.p": "Jikji mappa le idee di ricerca su primitive durevoli esistenti invece di trattare il “self-improvement” come un unico loop magico. Ogni meccanismo ha un confine di evidenza separato",
 "loop.research.stack.h": "Loop di controllo impilati",
 "loop.research.stack.p": "I loop di agente, verifica, event-driven, hill-climbing e approvazione umana possono comporsi, mentre il core Go e gli hook Lua mantengono espliciti i loro ruoli di enforcement",
 "loop.research.rho.h": "Proposte ispirate a RHO",
 "loop.research.rho.p": "Tracce passate possono proporre una direttiva harness, ma i gate meccanici di Pareto, qualità, Oracle, evidenza e approvazione dell'operatore decidono se può essere provata. Non si applica mai automaticamente",
 "img.tools.alt": "Catalogo di strumenti inciso che passa attraverso un gate di policy in esecutori locali, browser, container e remoti",
 "plate.tools.title": "ESECUZIONE TOOL",
 "plate.tools.meta": "UN PERCORSO POLICY, MOLTI RUNNER",
 "plate.tools.s1h": "Catalogo",
 "plate.tools.s1p": "Built-in, strumenti MCP ed estensioni installate espongono schemi tipizzati",
 "plate.tools.s2h": "Policy gate",
 "plate.tools.s2p": "Tenant, principal, azione, argomenti e ambiente producono allow, deny o ask",
 "plate.tools.s3h": "Runner + sandbox",
 "plate.tools.s3p": "L'esecuzione locale, Lua, Python, browser, container, SSH o remote-node rimane delimitata",
 "plate.tools.s4h": "Proof + audit",
 "plate.tools.s4p": "Gli output vengono sanificati, attribuiti, misurati e incorporati nel run come osservazioni",
 "plate.tools.cap": "La superficie di esecuzione può cambiare senza bypassare i controlli di autorizzazione, redazione, timeout o audit",
 "img.orch.alt": "Presse candidate indipendenti incise che convergono su sintesi, indicatori di verifica e una pressa di rilascio finale",
 "plate.orch.title": "TRINITY ENSEMBLE",
 "plate.orch.meta": "RISPOSTE DIVERSE · GATE AVVERSARIO",
 "plate.orch.s1h": "Candidati indipendenti",
 "plate.orch.s1p": "Modelli configurati distinti rispondono senza vedersi l'un l'altro",
 "plate.orch.s2h": "Sintesi",
 "plate.orch.s2p": "Un sintetizzatore concilia evidenza, disaccordi e alternative valide",
 "plate.orch.s3h": "Pannello del verificatore",
 "plate.orch.s3p": "Giudici separati votano ACCEPT o REVISE rispetto all'obiettivo e rubric.",
 "plate.orch.s4h": "Rilascia o rivedi",
 "plate.orch.s4p": "Il gate accetta o avvia un'altra revisione limitata; Oracle controlla separatamente la deriva della traiettoria.",
 "plate.orch.cap": "La diversità dei provider è configurazione, non una garanzia: un consiglio significativo richiede famiglie di modelli genuinamente distinte e credenziali valide.",
 "orch.evidence.tag": "Evidenza dell'harness",
 "orch.evidence.h2": "La politica di orchestrazione può evolvere; la qualità deve ancora essere misurata",
 "orch.evidence.p": "Il coordinatore, il verificatore e l'ottimizzatore ispirato a RHO sono meccanismi separati. Una proposta che supera l'ammissione è sicura da valutare, non provata migliore.",
 "orch.evidence.1h": "Ammissione meccanica prima",
 "orch.evidence.1p": "Aggiornamenti dell'harness dominati, in deriva o meccanicamente peggiori vengono rifiutati prima che una preferenza del modello possa rompere un vero pareggio.",
 "orch.evidence.2h": "Gate di rilascio umano",
 "orch.evidence.2p": "Una direttiva ammissibile viene archiviata come in attesa di approvazione. Un operatore la esamina prima dell'iniezione additiva e limitata nelle esecuzioni successive.",
 "orch.evidence.3h": "Confronto con dati esclusi",
 "orch.evidence.3p": "Gli harness di base e modificati necessitano dello stesso set di attività, ambiente, scorer e metriche attribuite. Un miglioramento nullo o negativo significa rifiutare la direttiva.",
 "img.memory.alt": "Sistema di memoria archivistica inciso che persiste, collega, consolida e recupera un pacchetto compatto di record.",
 "plate.memory.title": "MEMORIA DURABILE",
 "plate.memory.meta": "CON AMBITO TENANT · BASATO SU GALLEY",
 "plate.memory.s1h": "Osserva",
 "plate.memory.s1p": "Il ciclo forme emette eventi tipizzati, fatti, collegamenti e azioni di memoria esplicite.",
 "plate.memory.s2h": "Persisti in Galley",
 "plate.memory.s2p": "SQLite o un backend SQL condiviso registra lo stato durevole con migrazioni.",
 "plate.memory.s3h": "Consolida in Plate",
 "plate.memory.s3p": "Estrazione, deduplicazione, collegamenti grafici e consolidamento in background affinano il richiamo.",
 "plate.memory.s4h": "Recupera + compatta",
 "plate.memory.s4p": "La ricerca ibrida seleziona la memoria rilevante mentre la compattazione rispetta la finestra dei token.",
 "plate.memory.cap": "La durabilità è meccanica; la qualità dell'estrazione e del ranking rimane dipendente dal modello e dall'embedding e dovrebbe essere valutata sul tuo corpus.",
 "img.ontology.alt": "Motore inciso che trasforma documenti sorgente in un grafo di conoscenza collegato, query strutturata e violazione evidenziata.",
 "plate.ontology.title": "PERCORSO DI CONOSCENZA",
 "plate.ontology.meta": "DA CORPUS A GRAFO VERIFICABILE",
 "plate.ontology.s1h": "Corpus + osservazioni",
 "plate.ontology.s1p": "Documenti, dati relazionali e fatti di sistema misurati entrano attraverso strumenti governati.",
 "plate.ontology.s2h": "Grafo del lessico",
 "plate.ontology.s2p": "Entità, relazioni, situazioni, predicati e provenienza diventano record con ambito tenant.",
 "plate.ontology.s3h": "SPARQL + ricerca",
 "plate.ontology.s3p": "Query grafiche strutturate e recupero semantico espongono viste complementari.",
 "plate.ontology.s4h": "Revisione + azione",
 "plate.ontology.s4p": "La valutazione degli invarianti materializza le violazioni affinché l'agente possa ragionare e porvi rimedio.",
 "plate.ontology.cap": "Il grafo registra la provenienza e supporta predicati meccanici; l'estrazione di entità generata necessita ancora di una valutazione della qualità specifica del corpus.",
 "onto.foresight.tag": "Previsione basata sull'ontologia",
 "onto.foresight.h2": "Prova un futuro; non affermare mai di prevederlo",
 "onto.foresight.p": "La sandbox di previsione registra gli attori dello scenario nel grafo, deriva un piccolo insieme di persona degli stakeholder, esegue reazioni limitate e chiede a un ensemble con gate del verificatore un report mappato alla provenienza.",
 "onto.foresight.1h": "Input fondati",
 "onto.foresight.1p": "Ogni ramo del report deve tracciare una reazione di persona, un fatto grafico registrato e un seed sorgente. La sintesi non supportata viene rivista piuttosto che accettata.",
 "onto.foresight.2h": "Simulazione limitata",
 "onto.foresight.2p": "Il design di riferimento utilizza da quattro a sei persona in uno o due round, in modo che il costo rimanga limitato e ogni reazione rimanga verificabile.",
 "onto.foresight.note": "Questa è un'esplorazione strutturata di scenari, non una previsione, decisione o rivendicazione di accuratezza. La prosa del modello è non deterministica; la riproducibilità copre orchestrazione e provenienza.",
 "img.enterprise.alt": "Linea di controllo enterprise incisa che muove un'identità con ambito attraverso fasi di policy, proofing, denial e audit",
 "plate.enterprise.title": "PERCORSO DI CONTROLLO",
 "plate.enterprise.meta": "FAIL CHIUSO PER LAYER",
 "plate.enterprise.s1h": "Identità",
 "plate.enterprise.s1p": "Imprimatur risolve tenant, actor, scopes e credenziali in un principal.",
 "plate.enterprise.s2h": "Autorizzazione",
 "plate.enterprise.s2p": "Rubric valuta principal, action, tool, arguments e environment.",
 "plate.enterprise.s3h": "Proofing",
 "plate.enterprise.s3p": "PII, secrets e payload non sicuri vengono rilevati o redatti prima dell'esecuzione in uscita.",
 "plate.enterprise.s4h": "Audit + telemetria",
 "plate.enterprise.s4p": "Decisioni e risultati diventano prove tenant-aware senza secrets grezzi.",
 "plate.enterprise.cap": "La prontezza per la produzione dipende dalla configurazione esplicita: terminazione TLS, storage esterno di secrets, chiavi di backup, HA del database e routing degli alert sono responsabilità dell'operatore.",
 "notice.english": "Questa pagina rimane autorevole in inglese. La lingua selezionata si applica alla navigazione condivisa; non fare affidamento su una traduzione non ufficiale per termini legali.",
 "notice.english.ops": "Questa pagina rimane autorevole in inglese. La lingua selezionata si applica alla navigazione condivisa; segui il runbook in inglese durante un incidente.",
 "nav.code": "jikjicode",
 "jc.kicker": "jikjicode — l’agente di programmazione",
 "jc.title": "Un agente di programmazione che <span class=\"accent\">modifica come un compilatore</span>",
 "jc.sub": "jikjicode è una CLI autonoma per agenti di programmazione basata sul ciclo deterministico di Jikji. Combina chiamate a strumenti native del provider, modifiche precise, intelligenza del compilatore e dei language server, sessioni durevoli ed esecuzione protetta — in locale sul tuo computer o tramite delega a un server Jikji.",
 "jc.cmd.tag": "Una CLI, contratti di piattaforma espliciti",
 "jc.cmd.h2": "Funziona dove lavori",
 "jc.cmd.p": "Esegui <span class=\"mono\">jikjicode</span> in-process con un provider configurato oppure affida l'esecuzione a un server Jikji e al suo piano di policy. Gli artefatti senza CGO sono prodotti tramite build incrociata per Linux, macOS e Windows su amd64 e arm64. Linux amd64 è qualificato in modo nativo; gli altri target sono solo convalidati tramite compilazione e richiedono test dell'operatore. BSD non è supportato.",
 "jc.cmd.1.k": "Locale",
 "jc.cmd.1.v": "Per impostazione predefinita, il ciclo <code>forme</code> viene eseguito nello stesso processo con il tuo modello e con gli strumenti di programmazione sul tuo spazio di lavoro.",
 "jc.cmd.2.k": "Remoto",
 "jc.cmd.2.v": "Delega l’intera esecuzione a un server Jikji tramite <code>/v1/runs</code>; gli ambiti e il sandbox del server ne definiscono i limiti.",
 "jc.cmd.3.k": "Interattivo e singola esecuzione",
 "jc.cmd.3.v": "Su Linux qualificato, usa la TUI a schermo intero, la REPL a righe o <code>jikjicode exec</code>. <code>/resume</code>, le trascrizioni durevoli e l'output strutturato supportano l'automazione portabile; <code>/ps</code> ispeziona i terminali basati su PTY Unix. Windows ConPTY non è supportato.",
 "jc.cmd.4.k": "Configurazione",
 "jc.cmd.4.v": "<code>jikjicode init</code> crea la struttura di una configurazione; <code>jikjicode doctor</code> controlla il modello e l’ambiente prima di iniziare.",
 "jc.state.tag": "Contratto Durevole dell'Agente",
 "jc.state.h2": "Interrompi, riprendi e mantieni il modello sul lavoro",
 "jc.state.p": "Il ciclo di programmazione mantiene come contratti separati l'autorità di esecuzione, lo stato della conversazione, lo stato del piano e la capacità del contesto. In questo modo il lavoro di lunga durata è recuperabile senza trasformare la prosa del modello in flusso di controllo.",
 "jc.state.1.h": "Strumenti nativi, autorità tipizzata",
 "jc.state.1.p": "In locale, jikjicode abilita per impostazione predefinita le chiamate a strumenti tipizzate native del provider. Solo una chiamata tipizzata può essere eseguita; il testo dell'assistente simile a JSON resta testo di risposta e gli argomenti tipizzati non validi restituiscono un errore correlato senza eseguire lo strumento.",
 "jc.state.2.h": "Una vera ripresa, non un riepilogo incollato",
 "jc.state.2.p": "<code>/resume</code> ripristina atomicamente lo spazio di lavoro corrispondente, la trascrizione, la modalità dell'agente, il piano attivo, l'identità di trasporto e il checkpoint di contesto convalidato. Le sessioni importate non ereditano un'autorità di checkpoint attendibile.",
 "jc.state.3.h": "Continuazione limitata del contesto",
 "jc.state.3.p": "Quando la finestra del provider è nota, la compattazione preflight protegge la capacità prima della chiamata; il recupero dall'overflow offre il percorso reattivo. Un handoff versionato, con checksum e limitato preserva il lavoro corrente, le prove e i prossimi passi irrisolti.",
 "jc.state.4.h": "Piano, backlog e grafo delle attività restano distinti",
 "jc.state.4.p": "La modalità piano blocca modifiche, comandi, accesso alla rete e delega mentre <code>plan.write</code> costruisce l'artefatto di esecuzione; per uscirne serve un'approvazione esplicita. TODO resta il backlog dell'utente, mentre il grafo delle attività contiene le dipendenze di un piano accettato.",
 "jc.state.note": "<b>Confine di recupero:</b> le chiamate completate con prove durevoli corrispondenti sono protette dal replay. Gli effetti collaterali esterni richiedono comunque idempotenza downstream o riconciliazione da parte dell'operatore oltre un confine di crash ambiguo; Jikji non promette una garanzia universale exactly-once.",
 "jc.edit.tag": "MODIFICHE PRECISE",
 "jc.edit.h2": "Modifiche che rifiutano di operare su un file obsoleto",
 "jc.edit.p": "Una modalità di errore degli agenti di programmazione consiste nel modificare testo che ricordano male. jikjicode ancora ogni cambiamento a ciò che si trova realmente sul disco.",
 "jc.edit.1.h": "Modifiche ancorate a hash",
 "jc.edit.1.p": "<code>file.edit</code> vincola ogni cambiamento a un hash del contenuto e a un’ancora di riga. Se il file è cambiato, la modifica viene rifiutata — non applicata silenziosamente nel punto sbagliato — mentre una scala di corrispondenza tollerante e il recupero dell’ancora consentono di ritrovare la destinazione quando le righe si spostano.",
 "jc.edit.2.h": "Patch atomiche su più file",
 "jc.edit.2.p": "<code>file.apply_patch</code> applica una modifica su più file come un’unica unità e ripristina l’intero insieme in caso di errore parziale, senza lasciare il repository modificato a metà.",
 "jc.edit.3.h": "Diagnosi automatica dopo ogni modifica",
 "jc.edit.3.p": "Le modifiche a JSON e YAML vengono controllate sintatticamente all'interno del processo. Con l'esecuzione host esplicita abilitata, le diagnostiche dei pacchetti Go possono essere eseguite dopo una modifica e restituire gli errori nello stesso turno.",
 "jc.edit.4.h": "Sicuro con Unicode",
 "jc.edit.4.p": "Le modifiche e la corrispondenza degli identificatori tengono conto delle rune, quindi il codice sorgente multibyte e gli identificatori non ASCII vengono gestiti correttamente anziché danneggiati al confine di un byte.",
 "jc.ci.tag": "INTELLIGENZA DEL CODICE",
 "jc.ci.h2": "Legge il codice tramite il compilatore",
 "jc.ci.p": "Non si tratta di usare grep e sperare. Gli strumenti Go con riconoscimento dei tipi usano la vera toolchain; gli schemi strutturali coprono oltre 200 linguaggi; e i manifest di language-server considerati affidabili dall'operatore aggiungono simboli multilingua e grafi delle chiamate quando l'esecuzione host completa è abilitata esplicitamente.",
 "jc.ci.1.k": "Controllo dei tipi",
 "jc.ci.1.v": "diagnostica di livello compilatore per Go (go/packages), così il fatto che \"compili\" viene verificato, non presunto",
 "jc.ci.2.k": "Navigazione",
 "jc.ci.2.v": "— consapevole dei tipi per Go (go/types)",
 "jc.ci.3.k": "Ridenominazione",
 "jc.ci.3.v": "ridenominazione sicura, tra file e consapevole dei tipi per Go",
 "jc.ci.4.k": "Schema",
 "jc.ci.4.v": "— AST completo per Go e scansione delle definizioni basata su lexer (simile a ctags) per oltre 200 altri linguaggi",
 "jc.ci.5.k": "Multilingua tramite LSP",
 "jc.ci.5.v": "— simboli limitati e risultati chiamante/chiamato provenienti da un language server considerato affidabile dall'operatore, attivati in modo lazy in base all'estensione del file con accesso host completo esplicito",
 "jc.ci.note": "I processi language-server sono trattati come codice host affidabile: i manifest richiedono un percorso assoluto controllato dall'operatore, i frame e i risultati sono limitati, le fughe tramite link simbolici dello spazio di lavoro vengono rifiutate e le credenziali del provider vengono rimosse dall'ambiente figlio.",
 "jc.run.tag": "COMPILA, TESTA, DISTRIBUISCI",
 "jc.run.h2": "Esegue il progetto sotto il controllo che imposti",
 "jc.run.p": "Un agente di programmazione che non può eseguire i test sta solo tirando a indovinare. jikjicode esegue veri comandi di build e test, con un controllo dei rischi e un’approvazione umana facoltativa sotto il tuo controllo.",
 "jc.run.1.h": "Runner di comandi consapevole dell'host",
 "jc.run.1.p": "<code>shell.run</code> usa un adattatore shell POSIX su Linux e macOS e un adattatore <code>cmd.exe /C</code> con annullamento tramite Job Object su Windows. Il comportamento Linux è testato in modo nativo; macOS e Windows sono solo convalidati tramite compilazione incrociata e le sessioni Windows ConPTY non sono supportate. L'output limitato all'inizio e alla fine tiene i log rumorosi fuori dalla finestra di contesto.",
 "jc.run.2.h": "Sandbox basato sul rischio",
 "jc.run.2.p": "Una policy configurabile — <code>read-only</code>, <code>workspace-write</code> o <code>danger-full-access</code> — limita il rischio degli strumenti. L'isolamento profondo dei processi (namespace, procfs privato, Landlock, seccomp e cgroup opzionali) è disponibile solo su Linux. macOS Seatbelt e una sandbox OS Windows non sono implementati; le richieste che richiedono una sandbox OS falliscono in modalità chiusa.",
 "jc.run.3.h": "Chiede prima di agire",
 "jc.run.3.p": "Un livello di approvazione facoltativo (<code>--ask</code>) inserisce una persona nel processo per le azioni che la sandbox consente già. Un'approvazione mancante o non interattiva fallisce in modo sicuro; l'approvazione non sovrascrive mai un rifiuto della sandbox.",
 "jc.run.4.h": "Documentazione e attività a portata di mano",
 "jc.run.4.p": "<code>web.fetch</code> recupera la documentazione sotto il controllo del sandbox, mentre un tracker <code>todo</code> mantiene organizzata tra i turni una modifica in più passaggi.",
 "jc.run.note": "Lo stesso ciclo, un’interfaccia più ricca: jikjicode è il volto orientato alla programmazione del ciclo <a href=\"agent-loop.html\">forme</a> e si combina con gli <a href=\"use-cases.html\">esempi di orchestratore-esecutore e programmazione</a>.",
 "plate.code.title": "CICLO DI MODIFICA",
 "plate.code.meta": "ANCORATO, CONTROLLATO, REVERSIBILE",
 "plate.code.s1h": "Comprendi",
 "plate.code.s1p": "Il controllo dei tipi, i simboli e un grafo delle chiamate leggono il codice tramite il compilatore e i language server.",
 "plate.code.s2h": "Modifica",
 "plate.code.s2p": "Le modifiche ancorate a hash e le patch atomiche su più file rifiutano di operare su un file obsoleto.",
 "plate.code.s3h": "Verifica",
 "plate.code.s3p": "Ogni modifica mutante viene ricontrollata, mentre build e test vengono eseguiti tramite un adattatore di comandi specifico dell'host il cui target deve essere qualificato.",
 "plate.code.s4h": "Limita",
 "plate.code.s4p": "Un sandbox basato sul rischio con approvazione facoltativa controlla ciò che l’agente può eseguire.",
 "plate.code.cap": "Lo stesso ciclo deterministico forme, dotato di strumenti orientati alla programmazione: ogni modifica è ancorata, ogni comando è limitato."
};
